}

private func sanitizedInstacartStoreName(_ value: String?) -> String? {
    let trimmed = String(value ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
    guard !trimmed.isEmpty else { return nil }

    let lower = trimmed.lowercased()
    let allowlistedHints = [
        "metro",
        "no frills",
        "freshco",
        "food basics",
        "sobeys",
        "loblaws",
        "walmart",
        "costco",
        "real canadian superstore",
        "shoppers drug mart",
        "giant tiger",
        "adonis",
        "save on foods",
        "whole foods market"
    ]
    if allowlistedHints.contains(lower) {
        return trimmed
    }

    let storeishTerms = [
        "store", "market", "mart", "grocery", "grocer", "grocers", "foods", "superstore",
        "supermarket", "drug", "pharmacy", "wholesale", "express", "centre", "center"
    ]
    if storeishTerms.contains(where: { lower.contains($0) }) {
        return trimmed
    }

    let productishTerms = [
        "all purpose flour", "flour", "garlic", "onion", "chicken", "beef", "pork", "shrimp",
        "salmon", "tuna", "bread", "oil", "sauce", "salt", "pepper", "sugar", "honey", "rice",
        "pasta", "miso", "juice", "stock", "broth", "butter", "milk", "cheese", "cream", "yogurt",
        "lettuce", "cilantro", "parsley", "basil", "ginger", "cucumber", "potato", "tomato",
        "jalapeno", "chili", "paprika", "seasoning", "spice", "vanilla", "cinnamon"
    ]
    if productishTerms.contains(where: { lower.contains($0) }) {
        return nil
    }

    if ["true", "false", "null", "none", "undefined"].contains(lower) {
        return nil
    }

    if lower.hasPrefix("delivery by") || lower.hasPrefix("pickup by") || lower.hasPrefix("current price") || lower.hasPrefix("add ") {
        return nil
    }

    if trimmed.rangeOfCharacter(from: .letters) == nil {
        return nil
    }

    return trimmed
}

extension Notification.Name {
    static let recipeImportHistoryNeedsRefresh = Notification.Name("recipeImportHistoryNeedsRefresh")
    static let instacartRunSummaryDidUpdate = Notification.Name("instacartRunSummaryDidUpdate")
}

struct AppNotificationEvent: Identifiable, Codable, Hashable {
    let id: UUID
    let userID: String
    let kind: String
    let dedupeKey: String
    let title: String
    let body: String
    let subtitle: String?
    let imageURLString: String?
    let actionURLString: String?
    let actionLabel: String?
    let orderID: UUID?
    let planID: UUID?
    let recipeID: String?
    let metadata: [String: String]?
    let scheduledFor: Date
    let deliveredAt: Date?
    let seenAt: Date?
    let openedAt: Date?
    let createdAt: Date
    let updatedAt: Date?

    enum CodingKeys: String, CodingKey {
        case id
        case userID = "user_id"
        case kind
        case dedupeKey = "dedupe_key"
        case title
        case body
        case subtitle
        case imageURLString = "image_url"
        case actionURLString = "action_url"
        case actionLabel = "action_label"
        case orderID = "order_id"
        case planID = "plan_id"
        case recipeID = "recipe_id"
        case metadata
        case scheduledFor = "scheduled_for"
        case deliveredAt = "delivered_at"
        case seenAt = "seen_at"
        case openedAt = "opened_at"
        case createdAt = "created_at"
        case updatedAt = "updated_at"
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        id = try container.decode(UUID.self, forKey: .id)
        userID = try container.decode(String.self, forKey: .userID)
        kind = try container.decode(String.self, forKey: .kind)
        dedupeKey = try container.decode(String.self, forKey: .dedupeKey)
        title = try container.decode(String.self, forKey: .title)
        body = try container.decode(String.self, forKey: .body)
        subtitle = try container.decodeIfPresent(String.self, forKey: .subtitle)
        imageURLString = try container.decodeIfPresent(String.self, forKey: .imageURLString)
        actionURLString = try container.decodeIfPresent(String.self, forKey: .actionURLString)
        actionLabel = try container.decodeIfPresent(String.self, forKey: .actionLabel)
        orderID = try container.decodeIfPresent(UUID.self, forKey: .orderID)
        planID = try container.decodeIfPresent(UUID.self, forKey: .planID)
        recipeID = try container.decodeIfPresent(String.self, forKey: .recipeID)
        if let stringMetadata = try? container.decode([String: String].self, forKey: .metadata) {
            metadata = stringMetadata
        } else if let jsonMetadata = try? container.decode([String: AppNotificationMetadataScalar].self, forKey: .metadata) {
            metadata = jsonMetadata.reduce(into: [:]) { partialResult, pair in
                partialResult[pair.key] = pair.value.stringValue
            }
        } else {
            metadata = nil
        }
        scheduledFor = try container.decode(Date.self, forKey: .scheduledFor)
        deliveredAt = try container.decodeIfPresent(Date.self, forKey: .deliveredAt)
        seenAt = try container.decodeIfPresent(Date.self, forKey: .seenAt)
        openedAt = try container.decodeIfPresent(Date.self, forKey: .openedAt)
        createdAt = try container.decode(Date.self, forKey: .createdAt)
        updatedAt = try container.decodeIfPresent(Date.self, forKey: .updatedAt)
    }
}

private enum AppNotificationMetadataScalar: Codable, Hashable {
    case string(String)
    case number(Double)
    case bool(Bool)
    case null

    init(from decoder: Decoder) throws {
        let container = try decoder.singleValueContainer()
        if container.decodeNil() {
            self = .null
        } else if let value = try? container.decode(Bool.self) {
            self = .bool(value)
        } else if let value = try? container.decode(Double.self) {
            self = .number(value)
        } else {
            self = .string(try container.decode(String.self))
        }
    }

    func encode(to encoder: Encoder) throws {
        var container = encoder.singleValueContainer()
        switch self {
        case let .string(value):
            try container.encode(value)
        case let .number(value):
            try container.encode(value)
        case let .bool(value):
            try container.encode(value)
        case .null:
            try container.encodeNil()
        }
    }

    var stringValue: String {
        switch self {
        case let .string(value):
            return value
        case let .number(value):
            if value.rounded() == value {
                return String(Int(value))
            }
            return String(value)
        case let .bool(value):
            return value ? "true" : "false"
        case .null:
            return ""
        }
    }
}

