        case orderID = "order_id"
        case planID = "plan_id"
        case recipeID = "recipe_id"
        case metadata
        case scheduledFor = "scheduled_for"
    }
}

private enum AppNotificationEventServiceError: LocalizedError {
    case invalidRequest
    case invalidResponse
    case unauthorized
    case requestFailed(String)

    var errorDescription: String? {
        switch self {
        case .invalidRequest:
            return "Notification request was invalid."
        case .invalidResponse:
            return "Notification response was invalid."
        case .unauthorized:
            return "Notification session expired."
        case let .requestFailed(message):
            return message
        }
    }
}

final class SupabaseAppNotificationEventService {
    static let shared = SupabaseAppNotificationEventService()

    private init() {}

    func fetchPendingEvents(
        userID: String,
        accessToken: String? = nil,
        limit: Int = 40
    ) async throws -> [AppNotificationEvent] {
        if let backendEvents = try? await fetchEventsViaBackend(
            path: "/v1/notifications/pending",
            userID: userID,
            limit: limit
        ) {
            return backendEvents.filter { !$0.isHiddenFromNotifications }
        }
        return try await fetchEventsViaSupabase(
            userID: userID,
            accessToken: accessToken,
            deliveredOnly: true,
            limit: limit
        ).filter { !$0.isHiddenFromNotifications }
    }

    func fetchRecentEvents(
        userID: String,
        accessToken: String? = nil,
        limit: Int = 60
    ) async throws -> [AppNotificationEvent] {
        if let backendEvents = try? await fetchEventsViaBackend(
            path: "/v1/notifications/recent",
            userID: userID,
            limit: limit
        ) {
            return backendEvents.filter { !$0.isHiddenFromNotifications }
        }
        return try await fetchEventsViaSupabase(
            userID: userID,
            accessToken: accessToken,
            deliveredOnly: false,
            limit: limit
        ).filter { !$0.isHiddenFromNotifications }
    }

    func markDelivered(eventIDs: [UUID], userID: String, accessToken: String? = nil) async throws {
        if (try? await updateEventsViaBackend(eventIDs: eventIDs, userID: userID, path: "/v1/notifications/mark-delivered", bodyKey: "event_ids")) == true {
            return
        }
        try await updateViaSupabase(eventIDs: eventIDs, accessToken: accessToken, bodyKey: "delivered_at")
    }

    func markSeen(eventID: UUID, userID: String, accessToken: String? = nil) async throws {
        try await markSeen(eventIDs: [eventID], userID: userID, accessToken: accessToken)
    }

    func markSeen(eventIDs: [UUID], userID: String, accessToken: String? = nil) async throws {
        if (try? await updateEventsViaBackend(eventIDs: eventIDs, userID: userID, path: "/v1/notifications/mark-seen", bodyKey: "event_ids")) == true {
            return
        }
        try await updateViaSupabase(eventIDs: eventIDs, accessToken: accessToken, bodyKey: "seen_at")
    }

    func createEvent(
        userID: String,
        accessToken: String? = nil,
        kind: String,
        dedupeKey: String,
        title: String,
        body: String,
        subtitle: String? = nil,
        imageURLString: String? = nil,
        actionURLString: String? = nil,
        actionLabel: String? = nil,
        orderID: UUID? = nil,
        planID: UUID? = nil,
        recipeID: String? = nil,
        metadata: [String: String] = [:],
        scheduledFor: Date = .now
    ) async throws {
        if (try? await createEventViaBackend(
            userID: userID,
            kind: kind,
            dedupeKey: dedupeKey,
            title: title,
            body: body,
            subtitle: subtitle,
            imageURLString: imageURLString,
            actionURLString: actionURLString,
            actionLabel: actionLabel,
            orderID: orderID,
            planID: planID,
            recipeID: recipeID,
            metadata: metadata,
            scheduledFor: scheduledFor
        )) == true {
            return
        }

        guard let accessToken,
              !accessToken.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else {
            throw AppNotificationEventServiceError.unauthorized
        }

        try await createEventViaSupabase(
            userID: userID,
            accessToken: accessToken,
            kind: kind,
            dedupeKey: dedupeKey,
            title: title,
            body: body,
            subtitle: subtitle,
            imageURLString: imageURLString,
            actionURLString: actionURLString,
            actionLabel: actionLabel,
            orderID: orderID,
            planID: planID,
            recipeID: recipeID,
            metadata: metadata,
            scheduledFor: scheduledFor
        )
    }

    private func backendURL(path: String, queryItems: [URLQueryItem] = []) -> URL? {
        guard var components = URLComponents(string: "\(OunjeDevelopmentServer.primaryBaseURL)\(path)") else {
            return nil
        }
        components.queryItems = queryItems.isEmpty ? nil : queryItems
        return components.url
    }

    private func fetchEventsViaBackend(path: String, userID: String, limit: Int) async throws -> [AppNotificationEvent] {
        guard let url = backendURL(path: path, queryItems: [URLQueryItem(name: "user_id", value: userID), URLQueryItem(name: "limit", value: "\(limit)")]) else {
            throw AppNotificationEventServiceError.invalidRequest
        }

        let (data, response) = try await URLSession.shared.data(from: url)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw AppNotificationEventServiceError.invalidResponse
        }
        guard (200 ... 299).contains(httpResponse.statusCode) else {
            throw AppNotificationEventServiceError.requestFailed("Notification backend request failed (\(httpResponse.statusCode)).")
        }

        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        let payload = try decoder.decode(NotificationEventsResponse.self, from: data)
        return payload.items
    }

    private func updateEventsViaBackend(eventIDs: [UUID], userID: String, path: String, bodyKey: String) async throws -> Bool {
        let ids = eventIDs.map(\.uuidString)
        guard !ids.isEmpty else { return true }
        guard let url = backendURL(path: path) else {
            throw AppNotificationEventServiceError.invalidRequest
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try JSONSerialization.data(withJSONObject: [
            "user_id": userID,
            bodyKey: ids,
        ])

        let (data, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw AppNotificationEventServiceError.invalidResponse
        }
        guard (200 ... 299).contains(httpResponse.statusCode) else {
            throw AppNotificationEventServiceError.requestFailed("Notification backend request failed (\(httpResponse.statusCode)).")
        }
        _ = data
        return true
    }

    private func fetchEventsViaSupabase(
        userID: String,
        accessToken: String?,
        deliveredOnly: Bool,
        limit: Int
    ) async throws -> [AppNotificationEvent] {
        guard let encodedUserID = userID.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) else {
            throw AppNotificationEventServiceError.invalidRequest
        }
        let filter = deliveredOnly ? "&delivered_at=is.null" : ""
        guard let url = URL(
            string: "\(SupabaseConfig.url)/rest/v1/app_notification_events?select=*&user_id=eq.\(encodedUserID)\(filter)&order=created_at.desc,scheduled_for.desc&limit=\(limit)"
        ) else {
            throw AppNotificationEventServiceError.invalidRequest
        }

        guard let accessToken = accessToken?.trimmingCharacters(in: .whitespacesAndNewlines), !accessToken.isEmpty else {
            throw AppNotificationEventServiceError.unauthorized
        }

        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue(SupabaseConfig.anonKey, forHTTPHeaderField: "apikey")
        request.setValue("Bearer \(accessToken)", forHTTPHeaderField: "Authorization")

        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        let (data, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw AppNotificationEventServiceError.invalidResponse
        }
        if httpResponse.statusCode == 401 || httpResponse.statusCode == 403 {
            throw AppNotificationEventServiceError.unauthorized
        }
        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let errorPayload = try? JSONDecoder().decode(SupabaseRestErrorResponse.self, from: data)
            let fallback = deliveredOnly ? "Failed to load app notifications (\(httpResponse.statusCode))." : "Failed to load recent app notifications (\(httpResponse.statusCode))."
            throw AppNotificationEventServiceError.requestFailed(errorPayload?.message ?? errorPayload?.error ?? fallback)
        }
        return try decoder.decode([AppNotificationEvent].self, from: data)
    }

    private func updateViaSupabase(eventIDs: [UUID], accessToken: String?, bodyKey: String) async throws {
        let ids = eventIDs.map(\.uuidString)
        guard !ids.isEmpty else { return }
        guard let accessToken = accessToken?.trimmingCharacters(in: .whitespacesAndNewlines), !accessToken.isEmpty else {
            throw AppNotificationEventServiceError.unauthorized
        }
        let joined = ids.map { "\"\($0)\"" }.joined(separator: ",")
        let clause = "(\(joined))"
        let encodedClause = clause.addingPercentEncoding(withAllowedCharacters: .urlQueryAllowed) ?? clause
        guard let url = URL(string: "\(SupabaseConfig.url)/rest/v1/app_notification_events?id=in.\(encodedClause)") else {
            throw AppNotificationEventServiceError.invalidRequest
        }

        var request = URLRequest(url: url)
        request.httpMethod = "PATCH"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue(SupabaseConfig.anonKey, forHTTPHeaderField: "apikey")
        request.setValue("Bearer \(accessToken)", forHTTPHeaderField: "Authorization")
        let now = ISO8601DateFormatter().string(from: .now)
        request.httpBody = try JSONEncoder().encode([bodyKey: now])

        let (data, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw AppNotificationEventServiceError.invalidResponse
        }

        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let errorPayload = try? JSONDecoder().decode(SupabaseRestErrorResponse.self, from: data)
            let fallback = "Failed to update app notifications (\(httpResponse.statusCode))."
            throw AppNotificationEventServiceError.requestFailed(errorPayload?.message ?? errorPayload?.error ?? fallback)
        }
    }

    private func createEventViaBackend(
        userID: String,
        kind: String,
        dedupeKey: String,
        title: String,
        body: String,
        subtitle: String?,
        imageURLString: String?,
        actionURLString: String?,
        actionLabel: String?,
        orderID: UUID?,
        planID: UUID?,
        recipeID: String?,
        metadata: [String: String],
        scheduledFor: Date
    ) async throws -> Bool {
        guard let url = backendURL(path: "/v1/notifications") else {
            throw AppNotificationEventServiceError.invalidRequest
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        let formatter = ISO8601DateFormatter()
        let payload = AppNotificationEventWritePayload(
            userID: userID,
            kind: kind,
            dedupeKey: dedupeKey,
            title: title,
            body: body,
            subtitle: subtitle,
            imageURLString: imageURLString,
            actionURLString: actionURLString,
            actionLabel: actionLabel,
            orderID: orderID?.uuidString,
            planID: planID?.uuidString,
            recipeID: recipeID,
            metadata: metadata,
            scheduledFor: formatter.string(from: scheduledFor)
        )
        request.httpBody = try JSONEncoder().encode(["event": payload])

        let (data, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw AppNotificationEventServiceError.invalidResponse
        }
        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let errorPayload = try? JSONDecoder().decode(SupabaseRestErrorResponse.self, from: data)
            throw AppNotificationEventServiceError.requestFailed(errorPayload?.message ?? errorPayload?.error ?? "Failed to write app notification (\(httpResponse.statusCode)).")
        }
        return true
    }

    private func createEventViaSupabase(
        userID: String,
        accessToken: String,
        kind: String,
        dedupeKey: String,
        title: String,
        body: String,
        subtitle: String? = nil,
        imageURLString: String? = nil,
        actionURLString: String? = nil,
        actionLabel: String? = nil,
        orderID: UUID? = nil,
        planID: UUID? = nil,
        recipeID: String? = nil,
        metadata: [String: String] = [:],
        scheduledFor: Date = .now
    ) async throws {
        guard let url = URL(string: "\(SupabaseConfig.url)/rest/v1/app_notification_events?on_conflict=user_id,dedupe_key") else {
            throw AppNotificationEventServiceError.invalidRequest
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("resolution=merge-duplicates", forHTTPHeaderField: "Prefer")
        request.setValue(SupabaseConfig.anonKey, forHTTPHeaderField: "apikey")
        request.setValue("Bearer \(accessToken)", forHTTPHeaderField: "Authorization")

        let formatter = ISO8601DateFormatter()
        request.httpBody = try JSONEncoder().encode([
            AppNotificationEventWritePayload(
                userID: userID,
                kind: kind,
                dedupeKey: dedupeKey,
                title: title,
                body: body,
                subtitle: subtitle,
                imageURLString: imageURLString,
                actionURLString: actionURLString,
                actionLabel: actionLabel,
                orderID: orderID?.uuidString,
                planID: planID?.uuidString,
                recipeID: recipeID,
                metadata: metadata,
                scheduledFor: formatter.string(from: scheduledFor)
            )
        ])

        let (data, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw AppNotificationEventServiceError.invalidResponse
        }
        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let errorPayload = try? JSONDecoder().decode(SupabaseRestErrorResponse.self, from: data)
            let fallback = "Failed to write app notification (\(httpResponse.statusCode))."
            throw AppNotificationEventServiceError.requestFailed(errorPayload?.message ?? errorPayload?.error ?? fallback)
        }
    }

    private struct NotificationEventsResponse: Decodable {
        let items: [AppNotificationEvent]
    }
}

private extension AppNotificationEvent {
    var isHiddenFromNotifications: Bool {
        metadata?["hidden_from_notifications"]?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() == "true"
    }
}

private struct AppFeedbackMessageAttachment: Codable, Hashable {
    let fileName: String?
    let mimeType: String?
    let kind: String?

    enum CodingKeys: String, CodingKey {
        case fileName = "file_name"
        case mimeType = "mime_type"
        case kind
    }
}

private struct AppFeedbackMessage: Identifiable, Codable, Hashable {
    let id: UUID
    let userID: String
    let authorRole: String
    let body: String
    let attachments: [AppFeedbackMessageAttachment]
    let createdAt: Date

    enum CodingKeys: String, CodingKey {
        case id
        case userID = "user_id"
        case authorRole = "author_role"
        case body
        case attachments
        case createdAt = "created_at"
    }

    init(
        id: UUID,
        userID: String,
        authorRole: String,
        body: String,
        attachments: [AppFeedbackMessageAttachment],
        createdAt: Date
    ) {
        self.id = id
        self.userID = userID
        self.authorRole = authorRole
        self.body = body
        self.attachments = attachments
        self.createdAt = createdAt
    }

    init(from decoder: Decoder) throws {
        let container = try decoder.container(keyedBy: CodingKeys.self)
        id = try container.decode(UUID.self, forKey: .id)
        userID = try container.decodeIfPresent(String.self, forKey: .userID) ?? ""
        authorRole = try container.decodeIfPresent(String.self, forKey: .authorRole) ?? "system"
        body = try container.decodeIfPresent(String.self, forKey: .body) ?? ""
        attachments = try container.decodeIfPresent([AppFeedbackMessageAttachment].self, forKey: .attachments) ?? []

        let rawCreatedAt = try container.decodeIfPresent(String.self, forKey: .createdAt)
        createdAt = FeedbackDateParser.parse(rawCreatedAt) ?? Date()
    }
}

private enum FeedbackDateParser {
    private static let fractionalFormatter: ISO8601DateFormatter = {
        let formatter = ISO8601DateFormatter()
        formatter.formatOptions = [.withInternetDateTime, .withFractionalSeconds]
        return formatter
    }()

    private static let standardFormatter = ISO8601DateFormatter()

    static func parse(_ raw: String?) -> Date? {
        guard let raw = raw?.trimmingCharacters(in: .whitespacesAndNewlines), !raw.isEmpty else {
            return nil
        }
        return fractionalFormatter.date(from: raw) ?? standardFormatter.date(from: raw)
    }
}

private enum FeedbackServiceError: LocalizedError {
    case invalidRequest
    case invalidResponse
    case requestFailed(String)

    var errorDescription: String? {
        switch self {
        case .invalidRequest:
            return "Feedback request was invalid."
        case .invalidResponse:
            return "Feedback response was invalid."
        case let .requestFailed(message):
            return message
        }
    }
}

private struct FeedbackSubmissionResponse: Decodable {
    let items: [AppFeedbackMessage]
}

private final class OunjeFeedbackService {
    static let shared = OunjeFeedbackService()

    private init() {}

    func fetchMessages(userID: String) async throws -> [AppFeedbackMessage] {
        guard var components = URLComponents(string: "\(OunjeDevelopmentServer.primaryBaseURL)/v1/feedback") else {
            throw FeedbackServiceError.invalidRequest
        }
        components.queryItems = [URLQueryItem(name: "user_id", value: userID)]
        guard let url = components.url else {
            throw FeedbackServiceError.invalidRequest
        }

        let (data, response) = try await URLSession.shared.data(from: url)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw FeedbackServiceError.invalidResponse
        }
        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let errorPayload = try? JSONDecoder().decode(SupabaseRestErrorResponse.self, from: data)
            if Self.isMissingFeedbackTable(errorPayload?.message ?? errorPayload?.error ?? "") {
                return []
            }
            throw FeedbackServiceError.requestFailed(errorPayload?.message ?? errorPayload?.error ?? "Feedback could not be loaded (\(httpResponse.statusCode)).")
        }

        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        let payload = try decoder.decode(NotificationEventsResponse<AppFeedbackMessage>.self, from: data)
        return payload.items
    }

    func submitFeedback(
        userID: String,
        body: String,
        attachments: [AppFeedbackMessageAttachment]
    ) async throws -> FeedbackSubmissionResponse {
        guard let url = URL(string: "\(OunjeDevelopmentServer.primaryBaseURL)/v1/feedback") else {
            throw FeedbackServiceError.invalidRequest
        }

        struct Payload: Encodable {
            let userID: String
            let body: String
            let attachments: [AppFeedbackMessageAttachment]

            enum CodingKeys: String, CodingKey {
                case userID = "user_id"
                case body
                case attachments
            }
        }

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try JSONEncoder().encode(Payload(userID: userID, body: body, attachments: attachments))

        let (data, response) = try await URLSession.shared.data(for: request)
        guard let httpResponse = response as? HTTPURLResponse else {
            throw FeedbackServiceError.invalidResponse
        }
        guard (200 ... 299).contains(httpResponse.statusCode) else {
            let errorPayload = try? JSONDecoder().decode(SupabaseRestErrorResponse.self, from: data)
            let message = errorPayload?.message ?? errorPayload?.error ?? "Feedback could not be submitted (\(httpResponse.statusCode))."
            if Self.isMissingFeedbackTable(message) {
                return Self.localFallbackSubmission(body: body, attachments: attachments)
            }
            throw FeedbackServiceError.requestFailed(message)
        }

        let decoder = JSONDecoder()
        decoder.dateDecodingStrategy = .iso8601
        return try decoder.decode(FeedbackSubmissionResponse.self, from: data)
    }

    private struct NotificationEventsResponse<Item: Decodable>: Decodable {
        let items: [Item]
    }

    private static func isMissingFeedbackTable(_ message: String) -> Bool {
        let normalized = message.lowercased()
        return normalized.contains("app_feedback_messages")
            && (normalized.contains("schema cache") || normalized.contains("does not exist"))
    }

    private static func localFallbackSubmission(body: String, attachments: [AppFeedbackMessageAttachment]) -> FeedbackSubmissionResponse {
        let now = Date()
        let userMessage = AppFeedbackMessage(
            id: UUID(),
            userID: "",
            authorRole: "user",
            body: body,
            attachments: attachments,
            createdAt: now
        )

        return FeedbackSubmissionResponse(
            items: [userMessage]
        )
    }
}

struct StoreProductSnapshot: Hashable {
    let productID: String
    let displayPrice: String
}

enum StoreBillingError: LocalizedError {
    case authenticationRequired
    case productUnavailable
    case purchaseCancelled
    case purchasePending
    case purchaseUnverified

    var errorDescription: String? {
        switch self {
        case .authenticationRequired:
            return "Sign in again to manage your membership."
        case .productUnavailable:
            return "Membership products could not be loaded right now."
        case .purchaseCancelled:
            return "Purchase cancelled."
        case .purchasePending:
            return "Purchase is pending approval."
        case .purchaseUnverified:
            return "The App Store transaction could not be verified."
        }
    }
}

final class StoreKitMembershipBillingService {
    static let shared = StoreKitMembershipBillingService()

    private init() {}

    private let productIDsByPlan: [OunjeMembershipPlan: String] = [
        .init(tier: .plus, cadence: .monthly): "net.ounje.plus.monthly",
        .init(tier: .plus, cadence: .yearly): "net.ounje.plus.yearly",
        .init(tier: .autopilot, cadence: .monthly): "net.ounje.autopilot.monthly",
        .init(tier: .autopilot, cadence: .yearly): "net.ounje.autopilot.yearly",
    ]

    func fetchProductsByPlan() async throws -> [OunjeMembershipPlan: StoreProductSnapshot] {
        let products = try await Product.products(for: Array(productIDsByPlan.values))
        let productsByID = Dictionary(uniqueKeysWithValues: products.map { ($0.id, $0) })
        var snapshots: [OunjeMembershipPlan: StoreProductSnapshot] = [:]
        for (plan, productID) in productIDsByPlan {
            guard let product = productsByID[productID] else { continue }
            snapshots[plan] = StoreProductSnapshot(
                productID: product.id,
                displayPrice: product.displayPrice
            )
        }
        return snapshots
    }

    func fetchProductsByTier() async throws -> [OunjePricingTier: StoreProductSnapshot] {
        let productsByPlan = try await fetchProductsByPlan()
        var snapshots: [OunjePricingTier: StoreProductSnapshot] = [:]
        for (plan, snapshot) in productsByPlan {
            guard plan.cadence == .monthly || snapshots[plan.tier] == nil else { continue }
            snapshots[plan.tier] = snapshot
        }
        return snapshots
    }

    func purchase(plan: OunjeMembershipPlan) async throws -> AppUserEntitlement {
        guard let productID = productIDsByPlan[plan] else {
            throw StoreBillingError.productUnavailable
        }
        let products = try await Product.products(for: [productID])
        guard let product = products.first else {
            throw StoreBillingError.productUnavailable
        }

        let result = try await product.purchase()
        switch result {
        case .success(let verificationResult):
            let transaction = try verifiedTransaction(from: verificationResult)
            await transaction.finish()
            return entitlement(from: transaction, plan: plan, status: .active)
        case .pending:
            throw StoreBillingError.purchasePending
        case .userCancelled:
            throw StoreBillingError.purchaseCancelled
        @unknown default:
            throw StoreBillingError.productUnavailable
        }
    }

    func restorePurchases() async throws -> AppUserEntitlement? {
        try await AppStore.sync()
        return try await currentEntitlementSnapshot()
    }

    func currentEntitlementSnapshot() async throws -> AppUserEntitlement? {
        var resolved: AppUserEntitlement?

        for await verificationResult in StoreKit.Transaction.currentEntitlements {
            let transaction = try verifiedTransaction(from: verificationResult)
            guard let plan = plan(for: transaction.productID) else { continue }
            let candidate = entitlement(
                from: transaction,
                plan: plan,
                status: transaction.revocationDate == nil ? .active : .revoked
            )
            if shouldPrefer(candidate, over: resolved) {
                resolved = candidate
            }
        }

        return resolved
    }

    private func plan(for productID: String) -> OunjeMembershipPlan? {
        productIDsByPlan.first(where: { $0.value == productID })?.key
    }

    private func verifiedTransaction(from verificationResult: VerificationResult<StoreKit.Transaction>) throws -> StoreKit.Transaction {
        switch verificationResult {
        case .verified(let transaction):
            return transaction
        case .unverified:
            throw StoreBillingError.purchaseUnverified
        }
    }

    private func entitlement(from transaction: StoreKit.Transaction, plan: OunjeMembershipPlan, status: AppEntitlementStatus) -> AppUserEntitlement {
        AppUserEntitlement(
            userID: String(transaction.appAccountToken?.uuidString ?? ""),
            tier: plan.tier,
            status: status,
            source: .appStore,
            productID: transaction.productID,
            transactionID: String(transaction.id),
            originalTransactionID: String(transaction.originalID),
            expiresAt: transaction.expirationDate,
            updatedAt: Date(),
            metadata: [
                "environment": String(describing: transaction.environment),
                "ownership_type": String(describing: transaction.ownershipType),
                "billing_cadence": plan.cadence.rawValue
            ]
        )
    }

    private func shouldPrefer(_ lhs: AppUserEntitlement, over rhs: AppUserEntitlement?) -> Bool {
        guard let rhs else { return true }
        let rank: [OunjePricingTier: Int] = [
            .free: 0,
            .plus: 1,
            .autopilot: 2,
            .foundingLifetime: 3,
        ]
        let lhsRank = rank[lhs.effectiveTier] ?? 0
        let rhsRank = rank[rhs.effectiveTier] ?? 0
        if lhsRank != rhsRank {
            return lhsRank > rhsRank
        }
        return (lhs.expiresAt ?? .distantPast) > (rhs.expiresAt ?? .distantPast)
    }
}

enum SupabaseEntitlementServiceError: LocalizedError {
    case invalidRequest
    case invalidResponse
    case requestFailed(String)

    var errorDescription: String? {
        switch self {
        case .invalidRequest:
            return "Membership request could not be prepared."
        case .invalidResponse:
            return "Membership response was invalid."
        case .requestFailed(let message):
            return message
        }
    }
}

private struct EntitlementEnvelopeResponse: Decodable {
    let entitlement: AppUserEntitlement?
    let effectiveTier: OunjePricingTier

    enum CodingKeys: String, CodingKey {
        case entitlement
        case effectiveTier = "effectiveTier"
    }
}

final class SupabaseEntitlementService {
    static let shared = SupabaseEntitlementService()

    private init() {}

    func fetchCurrentEntitlement(userID: String, accessToken: String?) async throws -> AppUserEntitlement? {
        guard let accessToken = accessToken?.trimmingCharacters(in: .whitespacesAndNewlines),
              !accessToken.isEmpty
        else {
            throw SupabaseEntitlementServiceError.requestFailed("Membership session is missing.")
        }

        var lastError: Error?
        for baseURL in OunjeDevelopmentServer.workerCandidateBaseURLs {
            do {
                guard let url = URL(string: "\(baseURL)/v1/entitlements/current") else {
                    throw SupabaseEntitlementServiceError.invalidRequest
                }
                var request = URLRequest(url: url)
                request.httpMethod = "GET"
                request.timeoutInterval = 20
                request.setValue("Bearer \(accessToken)", forHTTPHeaderField: "Authorization")
                request.setValue(userID, forHTTPHeaderField: "x-user-id")
                let (data, response) = try await URLSession.shared.data(for: request)
                guard let httpResponse = response as? HTTPURLResponse else {
                    throw SupabaseEntitlementServiceError.invalidResponse
                }
                guard (200 ... 299).contains(httpResponse.statusCode) else {
                    let errorPayload = try? JSONDecoder().decode(SupabaseRestErrorResponse.self, from: data)
                    let fallback = "Membership refresh failed (\(httpResponse.statusCode))."
                    throw SupabaseEntitlementServiceError.requestFailed(errorPayload?.message ?? errorPayload?.error ?? fallback)
                }
                let decoder = JSONDecoder()
                decoder.dateDecodingStrategy = .iso8601
                let payload = try decoder.decode(EntitlementEnvelopeResponse.self, from: data)
                return payload.entitlement
            } catch {
                lastError = error
            }
        }

        throw lastError ?? SupabaseEntitlementServiceError.invalidResponse
    }

    @discardableResult
    func syncCurrentEntitlement(snapshot: AppUserEntitlement, userID: String, accessToken: String?) async throws -> AppUserEntitlement? {
        guard let accessToken = accessToken?.trimmingCharacters(in: .whitespacesAndNewlines),
              !accessToken.isEmpty
        else {
            throw SupabaseEntitlementServiceError.requestFailed("Membership session is missing.")
        }

        struct Payload: Encodable {
            let tier: String
            let status: String
            let source: String
            let productID: String?
            let transactionID: String?
            let originalTransactionID: String?
            let expiresAt: String?
            let metadata: [String: String]

            enum CodingKeys: String, CodingKey {
                case tier
                case status
                case source
                case productID = "product_id"
                case transactionID = "transaction_id"
                case originalTransactionID = "original_transaction_id"
                case expiresAt = "expires_at"
                case metadata
            }
        }

        var lastError: Error?
        for baseURL in OunjeDevelopmentServer.workerCandidateBaseURLs {
            do {
                guard let url = URL(string: "\(baseURL)/v1/entitlements/sync") else {
                    throw SupabaseEntitlementServiceError.invalidRequest
                }
                var request = URLRequest(url: url)
                request.httpMethod = "POST"
                request.timeoutInterval = 20
                request.setValue("application/json", forHTTPHeaderField: "Content-Type")
                request.setValue("Bearer \(accessToken)", forHTTPHeaderField: "Authorization")
                request.setValue(userID, forHTTPHeaderField: "x-user-id")
                request.httpBody = try JSONEncoder().encode(
                    Payload(
                        tier: snapshot.tier.rawValue,
                        status: snapshot.status.rawValue,
                        source: snapshot.source.rawValue,
                        productID: snapshot.productID,
                        transactionID: snapshot.transactionID,
                        originalTransactionID: snapshot.originalTransactionID,
                        expiresAt: snapshot.expiresAt?.ISO8601Format(),
                        metadata: snapshot.metadata
                    )
                )
                let (data, response) = try await URLSession.shared.data(for: request)
                guard let httpResponse = response as? HTTPURLResponse else {
                    throw SupabaseEntitlementServiceError.invalidResponse
                }
                guard (200 ... 299).contains(httpResponse.statusCode) else {
                    let errorPayload = try? JSONDecoder().decode(SupabaseRestErrorResponse.self, from: data)
                    let fallback = "Membership sync failed (\(httpResponse.statusCode))."
                    throw SupabaseEntitlementServiceError.requestFailed(errorPayload?.message ?? errorPayload?.error ?? fallback)
                }
                let decoder = JSONDecoder()
                decoder.dateDecodingStrategy = .iso8601
                let payload = try decoder.decode(EntitlementEnvelopeResponse.self, from: data)
                return payload.entitlement
            } catch {
                lastError = error
            }
        }

        throw lastError ?? SupabaseEntitlementServiceError.invalidResponse
    }
}

@MainActor
private final class AppNotificationCenterManager: ObservableObject {
    @Published private(set) var authorizationStatus: UNAuthorizationStatus = .notDetermined
    @Published private(set) var inboxEvents: [AppNotificationEvent] = []

    private let notificationCenter = UNUserNotificationCenter.current()
    private var isSyncing = false
    private var lastSyncedUserID: String?
    private var lastTrackingAuthFailureAt: Date?
    private var lastTrackingAuthFailureUserID: String?

    func syncForCurrentSession(_ session: AuthSession?) async {
        guard let session,
              !session.userID.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        else {
            return
        }

        guard !isSyncing else { return }
        isSyncing = true
        defer { isSyncing = false }

        await refreshInbox(for: session)
        await refreshAuthorizationStatus()
        if authorizationStatus == .notDetermined {
            await requestAuthorizationIfNeeded()
        }

        guard authorizationStatus == .authorized || authorizationStatus == .provisional else {
            return
        }

        do {
            if let accessToken = session.accessToken?.trimmingCharacters(in: .whitespacesAndNewlines),
               !accessToken.isEmpty,
               !shouldBackoffTracking(for: session.userID),
               let latestOrder = try? await GroceryOrderAPIService.shared.fetchLatestOrder(
                userID: session.userID,
                accessToken: accessToken
            ),
               latestOrder.needsTrackingRefresh {
                do {
                    try await GroceryOrderAPIService.shared.trackOrder(
                        orderID: latestOrder.id,
                        userID: session.userID,
                        accessToken: accessToken
                    )
                    lastTrackingAuthFailureUserID = nil
                    lastTrackingAuthFailureAt = nil
                } catch {
                    if isTrackingAuthorizationFailure(error) {
                        lastTrackingAuthFailureUserID = session.userID
                        lastTrackingAuthFailureAt = Date()
                    }
                }
            }

            let pendingEvents = try await SupabaseAppNotificationEventService.shared.fetchPendingEvents(
                userID: session.userID,
                accessToken: session.accessToken,
                limit: 40
            )
            if !pendingEvents.isEmpty {
                if authorizationStatus == .authorized || authorizationStatus == .provisional {
                    for event in pendingEvents {
                        try await scheduleNotificationIfNeeded(event)
                    }
                }

                try await SupabaseAppNotificationEventService.shared.markDelivered(
                    eventIDs: pendingEvents.map(\.id),
                    userID: session.userID,
                    accessToken: session.accessToken
                )
            }

            await refreshInbox(for: session)
            lastSyncedUserID = session.userID
        } catch {
            lastSyncedUserID = session.userID
        }
    }

    func refreshInbox(for session: AuthSession?) async {
        guard let session,
              !session.userID.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        else {
            inboxEvents = []
            return
        }

        do {
            inboxEvents = try await SupabaseAppNotificationEventService.shared.fetchRecentEvents(
                userID: session.userID,
                accessToken: session.accessToken,
                limit: 60
            )
        } catch {
            inboxEvents = []
        }
    }

    var unreadCount: Int {
        inboxEvents.reduce(into: 0) { count, event in
            if event.seenAt == nil { count += 1 }
        }
    }

    func markInboxEventsSeen(_ eventIDs: [UUID], session: AuthSession?) async {
        guard let session,
              !session.userID.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty,
              !eventIDs.isEmpty
        else {
            return
        }

        do {
            try await SupabaseAppNotificationEventService.shared.markSeen(
                eventIDs: eventIDs,
                userID: session.userID,
                accessToken: session.accessToken
            )
            await refreshInbox(for: session)
        } catch {
            // Keep the inbox list even if seen state fails to save.
        }
    }

    private func requestAuthorizationIfNeeded() async {
        do {
            let granted = try await notificationCenter.requestAuthorization(options: [.alert, .sound, .badge])
            authorizationStatus = granted ? .authorized : .denied
        } catch {
            authorizationStatus = .denied
        }
    }

    private func refreshAuthorizationStatus() async {
        let settings = await notificationCenter.notificationSettings()
        authorizationStatus = settings.authorizationStatus
    }

    private func scheduleNotificationIfNeeded(_ event: AppNotificationEvent) async throws {
        let identifier = "app-notification-\(event.id.uuidString)"
        let pending = await notificationCenter.pendingNotificationRequests()
        if pending.contains(where: { $0.identifier == identifier }) {
            return
        }

        let content = UNMutableNotificationContent()
        content.title = event.title
        content.body = event.body
        if let subtitle = event.subtitle, !subtitle.isEmpty {
            content.subtitle = subtitle
        }
        content.sound = .default
        content.userInfo = [
            "eventID": event.id.uuidString,
            "kind": event.kind,
            "actionURL": event.actionURLString ?? "",
            "orderID": event.orderID?.uuidString ?? "",
        ]

        let interval = max(1, event.scheduledFor.timeIntervalSinceNow)
        let trigger = UNTimeIntervalNotificationTrigger(timeInterval: interval, repeats: false)
        let request = UNNotificationRequest(identifier: identifier, content: content, trigger: trigger)
        try await notificationCenter.add(request)
    }

    private func shouldBackoffTracking(for userID: String) -> Bool {
        guard lastTrackingAuthFailureUserID == userID,
              let lastTrackingAuthFailureAt
        else {
            return false
        }
        return Date().timeIntervalSince(lastTrackingAuthFailureAt) < 15 * 60
    }

    private func isTrackingAuthorizationFailure(_ error: Error) -> Bool {
        let message = error.localizedDescription.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        return message.contains("authorization")
            || message.contains("jwt")
            || message.contains("token is expired")
            || message.contains("401")
            || message.contains("userauthenticationrequired")
    }
}

@MainActor
private final class AppToastCenter: ObservableObject {
    @Published var toast: AppToast?

    private var dismissTask: Task<Void, Never>?

    func showSavedRecipe(_ recipe: DiscoverRecipeCardData) {
        showSavedRecipe(
            title: recipe.title,
            thumbnailURLString: recipe.imageURLString ?? recipe.heroImageURLString,
            destination: .recipe(recipe)
        )
    }

    func showSavedRecipe(title: String, thumbnailURLString: String? = nil) {
        showSavedRecipe(title: title, thumbnailURLString: thumbnailURLString, destination: nil)
    }

    func showSavedRecipe(
        title: String,
        thumbnailURLString: String? = nil,
        destination: AppToastDestination?
    ) {
        show(
            title: "Saved",
            subtitle: title,
            systemImage: "bookmark.fill",
            thumbnailURLString: thumbnailURLString,
            destination: destination
        )
    }

    func showUnsavedRecipe(_ recipe: DiscoverRecipeCardData) {
        showUnsavedRecipe(
            title: recipe.title,
            thumbnailURLString: recipe.imageURLString ?? recipe.heroImageURLString,
            destination: .recipe(recipe)
        )
    }

    func showUnsavedRecipe(title: String, thumbnailURLString: String? = nil) {
        showUnsavedRecipe(title: title, thumbnailURLString: thumbnailURLString, destination: nil)
    }

    func showUnsavedRecipe(
        title: String,
        thumbnailURLString: String? = nil,
        destination: AppToastDestination?,
        actionTitle: String? = nil,
        action: (() -> Void)? = nil
    ) {
        show(
            title: "Removed from saved",
            subtitle: title,
            systemImage: "bookmark.slash.fill",
            thumbnailURLString: thumbnailURLString,
            destination: destination,
            actionTitle: actionTitle,
            action: action
        )
    }

    func show(
        title: String,
        subtitle: String? = nil,
        systemImage: String = "checkmark.circle.fill",
        thumbnailURLString: String? = nil,
        destination: AppToastDestination? = nil,
        actionTitle: String? = nil,
        action: (() -> Void)? = nil
    ) {
        dismissTask?.cancel()
        withAnimation(.spring(response: 0.36, dampingFraction: 0.82)) {
            toast = AppToast(
                title: title,
                subtitle: subtitle,
                systemImage: systemImage,
                thumbnailURLString: thumbnailURLString,
                destination: destination,
                actionTitle: actionTitle,
                action: action
            )
        }

        dismissTask = Task { [weak self] in
            try? await Task.sleep(nanoseconds: 3_000_000_000)
            guard !Task.isCancelled else { return }
            await MainActor.run {
                guard let self else { return }
                withAnimation(.spring(response: 0.36, dampingFraction: 0.92)) {
                    self.toast = nil
                }
            }
        }
    }

    func dismiss() {
        dismissTask?.cancel()
        dismissTask = nil
        withAnimation(.spring(response: 0.36, dampingFraction: 0.92)) {
            toast = nil
        }
    }
}

@MainActor
private final class SharedRecipeImportInboxStore: ObservableObject {
    @Published private(set) var envelopes: [SharedRecipeImportEnvelope] = []

    var badgeCount: Int {
        envelopes.count
    }

    var failedCount: Int {
        envelopes.filter(\.isRetryNeeded).count
    }

    var queuedCount: Int {
        envelopes.filter(\.isLiveQueueState).count
    }

    func refresh() async {
        try? SharedRecipeImportInbox.reconcileStaleProcessingEnvelopes()
        envelopes = (try? SharedRecipeImportInbox.readAll()) ?? []
    }

    func envelope(withID envelopeID: String) -> SharedRecipeImportEnvelope? {
        envelopes.first(where: { $0.id == envelopeID })
    }

    func reconcileCompletedImports(_ completedItems: [RecipeImportCompletedItem]) async {
        let currentEnvelopes = (try? SharedRecipeImportInbox.readAll()) ?? []
        guard !currentEnvelopes.isEmpty else {
            envelopes = []
            return
        }

        let matchedIDs: [String] = completedItems.isEmpty
            ? []
            : currentEnvelopes
                .filter { envelope in
                    guard !envelope.isPinnedTypedImport else { return false }
                    return completedItems.contains(where: { $0.matches(envelope: envelope) })
                }
                .map(\.id)

        if !matchedIDs.isEmpty {
            matchedIDs.forEach { envelopeID in
                try? SharedRecipeImportInbox.delete(envelopeID: envelopeID)
            }
        }

        let remainingEnvelopes = currentEnvelopes.filter { envelope in
            !matchedIDs.contains(envelope.id)
        }

        for envelope in remainingEnvelopes where !envelope.isPinnedTypedImport {
            guard let jobID = envelope.jobID?.trimmingCharacters(in: .whitespacesAndNewlines),
                  !jobID.isEmpty else {
                continue
            }

            do {
                let response = try await RecipeImportAPIService.shared.fetchImportJob(jobID: jobID)
                let backendProcessingState = response.job.status.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
                let normalizedCanonicalURL = [
                    response.recipeDetail?.originalRecipeURLString,
                    response.recipeDetail?.recipeURLString,
                    response.job.sourceURL
                ]
                .compactMap { raw -> String? in
                    let trimmed = raw?.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines) ?? ""
                    return trimmed.isEmpty ? nil : trimmed
                }
                .first
                let isTerminalServerState = ["saved", "needs_review", "draft"].contains(backendProcessingState)

                if isTerminalServerState || response.recipe != nil {
                    try? SharedRecipeImportInbox.delete(envelopeID: envelope.id)
                    continue
                }

                let healedEnvelope = SharedRecipeImportEnvelope(
                    id: envelope.id,
                    createdAt: envelope.createdAt,
                    jobID: response.job.id,
                    targetState: envelope.targetState,
                    sourceText: envelope.sourceText,
                    sourceURLString: envelope.sourceURLString,
                    canonicalSourceURLString: normalizedCanonicalURL,
                    sourceApp: envelope.sourceApp,
                    attachments: envelope.attachments,
                    processingState: backendProcessingState.isEmpty ? envelope.normalizedProcessingState : backendProcessingState,
                    attemptCount: envelope.attemptCount,
                    lastAttemptAt: envelope.lastAttemptAt,
                    lastError: response.job.errorMessage ?? envelope.lastError,
                    updatedAt: Date()
                )
                try? SharedRecipeImportInbox.update(healedEnvelope)
            } catch {
                continue
            }
        }

        await refresh()
    }
}

@MainActor
private final class RecipeImportHistoryStore: ObservableObject {
    @Published private(set) var completedItems: [RecipeImportCompletedItem] = []

    var badgeCount: Int {
