    private var selectableCuisineOptions: [CuisinePreference] {
        let filtered = CuisinePreference.allCases.filter {
            $0 != .vegan
        }

        let preferredOrder: [CuisinePreference] = [
            .american,
            .mexican,
            .southern,
            .cajun,
            .caribbean,
            .brazilian,
            .italian,
            .french,
            .spanish,
            .portuguese,
            .mediterranean,
            .greek,
