    private func autonomySubtitle(for option: OrderingAutonomyLevel) -> String {
        switch option {
        case .suggestOnly:
            return "The app builds a plan, but the user stays in full control."
        case .approvalRequired:
            return "The app can build the cart, but you approve checkout."
        case .autoOrderWithinBudget:
            return "Plus unlocks auto-checkout when totals stay inside your budget."
        case .fullyAutonomousGuardrails:
            return "Autopilot unlocks end-to-end ordering with timing and spend guardrails."
        }
    }

    private func selectAddressSuggestion(_ suggestion: AddressSuggestion) async {
        guard let address = await addressAutocomplete.resolve(suggestion) else { return }

        await MainActor.run {
            addressLine1 = address.line1
            city = address.city
            region = address.region
            postalCode = address.postalCode
            if !address.line2.isEmpty {
                addressLine2 = address.line2
            }
            addressAutocomplete.query = ""
        }
    }

    private func clearAddress() {
        addressLine1 = ""
        addressLine2 = ""
        city = ""
        region = ""
        postalCode = ""
        deliveryNotes = ""
        addressAutocomplete.query = ""
    }

    fileprivate enum SetupStep: Int, CaseIterable {
        case name
        case identity
        case cuisines
        case household
        case kitchen
        case budget
        case ordering
        case address

        var index: Int { rawValue }

        var title: String {
            switch self {
            case .name:
                return "Meet Ounje"
            case .identity:
                return "Food rules"
            case .cuisines:
                return "Taste"
            case .household:
                return "Prep rhythm"
            case .kitchen:
                return "Who we're feeding"
            case .budget:
                return "Cart budget"
            case .ordering:
                return "Autopilot"
            case .address:
                return "Delivery"
            }
        }

        var subtitle: String {
            switch self {
            case .name:
                return "Ounje turns a few signals into prep, recurring meals, and a cart."
            case .identity:
                return "Allergies and hard stops beat every recipe suggestion."
            case .cuisines:
                return "These are the plates Ounje should reach for first."
            case .household:
                return "This sets your delivery timing and recurring meal loop."
            case .kitchen:
                return "Tell Ounje how many people each prep should carry."
            case .budget:
                return "Set the target spend and how hard Ounje should defend it."
            case .ordering:
                return "Choose whether Ounje prepares the cart or helps move checkout along."
            case .address:
                return "Connect your cart lane and add delivery details when you're ready."
            }
        }

        var prompt: String {
            switch self {
            case .name:
                return "Tell Ounje who it is planning for."
            case .identity:
                return "Set the rules Ounje cannot break."
            case .cuisines:
                return "Point Ounje toward the food you actually want."
            case .household:
                return "Choose how your prep week should run."
            case .kitchen:
                return "Choose the crowd Ounje is cooking for."
            case .budget:
                return "Set the cart guardrails."
            case .ordering:
                return "Decide how autonomous Ounje can be."
            case .address:
                return "Set the handoff details for checkout."
            }
        }

        var plateEmojis: [String] {
            switch self {
            case .name:
                return ["🍽️", "📝", "🛒"]
            case .identity:
                return ["✅", "🥗", "🛡️"]
            case .cuisines:
                return ["🍛", "🌮", "🍜"]
            case .household:
                return ["📅", "🍱", "🔁"]
            case .kitchen:
                return ["🍳", "🥘", "🔥"]
            case .budget:
                return ["🛒", "$", "✓"]
            case .ordering:
                return ["🏠", "🛍️", "→"]
            case .address:
                return ["📍", "📝", "🚪"]
            }
        }

        var symbolName: String {
            switch self {
            case .name:
                return "person.crop.circle.fill"
            case .identity:
                return "checklist"
            case .cuisines:
                return "globe.americas.fill"
            case .household:
                return "person.2.fill"
            case .kitchen:
                return "person.2.fill"
            case .budget:
                return "dollarsign.circle.fill"
            case .ordering:
                return "cart.fill"
            case .address:
                return "house.fill"
            }
        }

        var next: SetupStep? {
            SetupStep(rawValue: rawValue + 1)
        }

        var previous: SetupStep? {
            SetupStep(rawValue: rawValue - 1)
        }

        static func resumeStep(from rawValue: Int) -> SetupStep {
            let clampedValue = min(max(rawValue, SetupStep.name.rawValue), SetupStep.address.rawValue)
            return SetupStep(rawValue: clampedValue) ?? .name
        }
    }
}

