private enum TurtleOnboardingSceneMode: Equatable {
    case name
    case rules

    var turtleWidthRatio: CGFloat {
        switch self {
        case .name:
            return 0.26
        case .rules:
            return 0.22
        }
    }

    var maxTurtleWidth: CGFloat {
        switch self {
        case .name:
            return 96
        case .rules:
            return 78
        }
    }

    var sideInset: CGFloat {
        switch self {
        case .name:
            return 64
        case .rules:
            return 50
        }
    }

    var yBaseRatio: CGFloat {
        switch self {
        case .name:
            return 0.72
        case .rules:
            return 0.66
        }
    }

    var waveHeight: CGFloat {
        switch self {
        case .name:
            return 28
        case .rules:
            return 28
        }
    }

    var cornerRadius: CGFloat {
        switch self {
        case .name:
            return 0
        case .rules:
            return 26
        }
    }
}

private struct TurtleOnboardingScene: View {
    let prompt: String
    let mode: TurtleOnboardingSceneMode

    var body: some View {
        ZStack {
            Image("OnboardingTurtleHabitat")
                .resizable()
                .scaledToFill()

            LinearGradient(
                colors: [
                    Color.black.opacity(0.08),
                    Color.black.opacity(0.28)
                ],
                startPoint: .top,
                endPoint: .bottom
            )

            if mode == .rules {
                TurtleGuardrailMarkers()
            }

            TurtleNamePrompt(prompt: prompt, mode: mode)
                .padding(.horizontal, 12)
                .padding(.vertical, 14)
        }
        .clipShape(RoundedRectangle(cornerRadius: mode.cornerRadius, style: .continuous))
        .overlay {
            if mode == .rules {
                RoundedRectangle(cornerRadius: mode.cornerRadius, style: .continuous)
                    .stroke(Color.white.opacity(0.08), lineWidth: 1)
            }
        }
        .overlay(alignment: .bottom) {
            if mode.waveHeight > 0 {
                ZStack(alignment: .top) {
                    OnboardingHabitatWaveFill()
                        .fill(OunjePalette.background)

                    OnboardingHabitatWaveLine()
                        .stroke(Color.white.opacity(0.08), lineWidth: 1)
                }
