                            .stroke(isSelected ? accent.opacity(0.9) : Color.white.opacity(0.16), lineWidth: 1.4)
                    )
            )
            .scaleEffect(isSelected ? 1.015 : 1)
            .animation(OunjeMotion.quickSpring, value: isSelected)
        }
        .buttonStyle(OunjeCardPressButtonStyle())
    }
}

