private struct Triangle: Shape {
    func path(in rect: CGRect) -> Path {
        var path = Path()
        path.move(to: CGPoint(x: rect.midX, y: rect.minY))
        path.addLine(to: CGPoint(x: rect.maxX, y: rect.maxY))
        path.addLine(to: CGPoint(x: rect.minX, y: rect.maxY))
        path.closeSubpath()
        return path
    }
}

private struct Diamond: Shape {
    func path(in rect: CGRect) -> Path {
        var path = Path()
        path.move(to: CGPoint(x: rect.midX, y: rect.minY))
        path.addLine(to: CGPoint(x: rect.maxX, y: rect.midY))
        path.addLine(to: CGPoint(x: rect.midX, y: rect.maxY))
        path.addLine(to: CGPoint(x: rect.minX, y: rect.midY))
        path.closeSubpath()
        return path
    }
}

private struct DiagonalCross: View {
    let color: Color
    let lineWidth: CGFloat

    var body: some View {
        GeometryReader { proxy in
            ZStack {
                Rectangle()
                    .fill(color)
                    .frame(width: proxy.size.width * 1.5, height: lineWidth)
                    .rotationEffect(.degrees(34))
                Rectangle()
                    .fill(color)
                    .frame(width: proxy.size.width * 1.5, height: lineWidth)
                    .rotationEffect(.degrees(-34))
            }
        }
    }
}

private struct StarShape: Shape {
    let points: Int

    func path(in rect: CGRect) -> Path {
        let center = CGPoint(x: rect.midX, y: rect.midY)
        let outerRadius = min(rect.width, rect.height) / 2
        let innerRadius = outerRadius * 0.42
        let angle = Double.pi / Double(points)

        var path = Path()
        for index in 0..<(points * 2) {
            let radius = index.isMultiple(of: 2) ? outerRadius : innerRadius
            let pointAngle = (Double(index) * angle) - (.pi / 2)
            let point = CGPoint(
                x: center.x + CGFloat(cos(pointAngle)) * radius,
                y: center.y + CGFloat(sin(pointAngle)) * radius
            )

            if index == 0 {
                path.move(to: point)
            } else {
                path.addLine(to: point)
            }
        }
        path.closeSubpath()
        return path
    }
}

private struct OnboardingChoicePill: View {
    let title: String
    let emoji: String?
    let isSelected: Bool
    let accent: Color
    let action: () -> Void

    var body: some View {
        Button(action: action) {
            HStack(spacing: 8) {
                if let emoji {
                    Text(emoji)
                        .font(.system(size: 18))
                        .frame(width: 26, height: 26)
                } else {
                    Image(systemName: isSelected ? "checkmark.seal.fill" : "sparkles")
                        .font(.system(size: 13, weight: .black))
                        .foregroundStyle(isSelected ? .black : OunjePalette.secondaryText)
                        .frame(width: 26, height: 26)
