private struct OnboardingStepperRow: View {
    let title: String
    let value: Int
    let range: ClosedRange<Int>
    let accent: Color
    let onChange: (Int) -> Void

    var body: some View {
        HStack(spacing: 12) {
            Text(title)
                .font(.system(size: 14, weight: .black))
                .foregroundStyle(OunjePalette.primaryText)

            Spacer(minLength: 0)

            Button {
                onChange(max(range.lowerBound, value - 1))
            } label: {
                Image(systemName: "minus")
                    .font(.system(size: 13, weight: .black))
                    .frame(width: 34, height: 34)
            }
            .disabled(value <= range.lowerBound)

            Text("\(value)")
                .font(.system(size: 18, weight: .heavy, design: .rounded))
                .foregroundStyle(OunjePalette.primaryText)
                .frame(width: 34)

            Button {
                onChange(min(range.upperBound, value + 1))
            } label: {
                Image(systemName: "plus")
                    .font(.system(size: 13, weight: .black))
                    .frame(width: 34, height: 34)
            }
            .disabled(value >= range.upperBound)
        }
        .buttonStyle(.plain)
        .padding(.horizontal, 12)
        .padding(.vertical, 10)
        .background(
            RoundedRectangle(cornerRadius: 18, style: .continuous)
                .fill(OunjePalette.elevated)
                .overlay(
                    RoundedRectangle(cornerRadius: 18, style: .continuous)
                        .stroke(OunjePalette.stroke, lineWidth: 1)
                )
        )
        .tint(OunjePalette.primaryText)
    }
}

