private func onboardingEmoji(for value: String) -> String? {
    let lowered = value.lowercased()

    if lowered.contains("omnivore") { return "🍽" }
    if lowered.contains("halal") || lowered.contains("kosher") { return "🛡" }
    if lowered.contains("vegetarian") || lowered.contains("vegan") { return "🌿" }
    if lowered.contains("pescatarian") || lowered.contains("seafood") || lowered.contains("salmon") { return "🐟" }
    if lowered.contains("gluten") { return "🌾" }
    if lowered.contains("dairy") { return "🥛" }
    if lowered.contains("protein") || lowered.contains("macros") { return "💪" }
    if lowered.contains("speed") { return "⚡️" }
    if lowered.contains("taste") { return "😋" }
    if lowered.contains("cost") { return "💸" }
    if lowered.contains("variety") { return "🎲" }
    if lowered.contains("family") { return "👥" }
    if lowered.contains("cleanup") { return "🧼" }
    if lowered.contains("repeat") { return "🔁" }
    if lowered.contains("rice") || lowered.contains("jollof") || lowered.contains("biryani") { return "🍚" }
    if lowered.contains("chicken") { return "🍗" }
    if lowered.contains("pasta") { return "🍝" }
    if lowered.contains("taco") || lowered.contains("burrito") { return "🌮" }
    if lowered.contains("salad") { return "🥗" }
    if lowered.contains("wrap") { return "🌯" }
    if lowered.contains("stir") { return "🥢" }
    if lowered.contains("mushroom") { return "🍄" }
    if lowered.contains("olive") { return "🫒" }
    if lowered.contains("tofu") { return "🧈" }
    return nil
}

@MainActor
private final class SavedRecipesStore: ObservableObject {
    @Published private(set) var savedRecipes: [DiscoverRecipeCardData] = []

    private let legacyKey = "ounje-saved-recipes-v1"
    private let keyPrefix = "ounje-saved-recipes-v2"
    private let deletedKeyPrefix = "ounje-saved-recipes-deleted-v1"
    private let toastCenter: AppToastCenter
    private var activeUserID: String?
    private var deletedSavedRecipeIDs: Set<String> = []

    init(toastCenter: AppToastCenter) {
        self.toastCenter = toastCenter
        load(for: nil)
    }

    func isSaved(_ recipe: DiscoverRecipeCardData) -> Bool {
        savedRecipes.contains { $0.id == recipe.id }
    }

    func bootstrap(authSession: AuthSession?) async {
        let resolvedUserID = authSession?.userID

        if activeUserID != resolvedUserID {
            activeUserID = resolvedUserID
            load(for: resolvedUserID)
        }

        guard let authSession else { return }

        do {
            let remoteRecipes = try await SupabaseSavedRecipesService.shared.fetchSavedRecipes(userID: authSession.userID)
            let mergedRecipes = merge(local: savedRecipes, remote: remoteRecipes)

            if mergedRecipes != savedRecipes {
                savedRecipes = mergedRecipes
                persist()
            }

            if !deletedSavedRecipeIDs.isEmpty {
                await reconcilePendingDeletes(userID: authSession.userID)
            }

            let remoteIDs = Set(remoteRecipes.map(\.id)).subtracting(deletedSavedRecipeIDs)
            let unsyncedLocalRecipes = mergedRecipes.filter { !remoteIDs.contains($0.id) && !deletedSavedRecipeIDs.contains($0.id) }
            if !unsyncedLocalRecipes.isEmpty {
                try await SupabaseSavedRecipesService.shared.upsertSavedRecipes(
                    userID: authSession.userID,
                    recipes: unsyncedLocalRecipes
                )
            }
        } catch {
            // Keep local saves available even when network sync fails.
        }
    }

    func toggle(_ recipe: DiscoverRecipeCardData) {
        let shouldSave = !isSaved(recipe)

        if shouldSave {
            deletedSavedRecipeIDs.remove(recipe.id)
            savedRecipes.removeAll { $0.id == recipe.id }
            savedRecipes.insert(recipe, at: 0)
            toastCenter.showSavedRecipe(recipe)
        } else {
            savedRecipes.removeAll { $0.id == recipe.id }
            deletedSavedRecipeIDs.insert(recipe.id)
            toastCenter.showUnsavedRecipe(
                title: recipe.title,
                thumbnailURLString: recipe.imageURLString ?? recipe.heroImageURLString,
                destination: nil,
                actionTitle: "Undo",
                action: { [weak self] in
                    self?.restoreSavedRecipe(recipe)
                }
            )
        }
        persist()

        guard let userID = activeUserID else { return }

        Task(priority: .utility) {
            do {
                if shouldSave {
                    try await SupabaseSavedRecipesService.shared.upsertSavedRecipes(
                        userID: userID,
                        recipes: [recipe]
                    )
                } else {
                    try await SupabaseSavedRecipesService.shared.deleteSavedRecipe(
                        userID: userID,
                        recipeID: recipe.id
                    )
                }
            } catch {
                // Local persistence remains the source of truth when sync fails.
            }
        }
    }

    func saveImportedRecipe(_ recipe: DiscoverRecipeCardData, showToast: Bool = true) {
        let existing = savedRecipes.first(where: { $0.id == recipe.id })
        let resolved = mergeRecipeCards(primary: recipe, fallback: existing)
        deletedSavedRecipeIDs.remove(recipe.id)
        savedRecipes.removeAll { $0.id == recipe.id }
        savedRecipes.insert(resolved, at: 0)
        persist()

        if showToast {
            toastCenter.showSavedRecipe(resolved)
        }
    }

    private func restoreSavedRecipe(_ recipe: DiscoverRecipeCardData) {
        deletedSavedRecipeIDs.remove(recipe.id)
        savedRecipes.removeAll { $0.id == recipe.id }
        savedRecipes.insert(recipe, at: 0)
        persist()
        toastCenter.dismiss()

        guard let userID = activeUserID else { return }
        Task(priority: .utility) {
            try? await SupabaseSavedRecipesService.shared.upsertSavedRecipes(
                userID: userID,
                recipes: [recipe]
            )
        }
    }

    private func persist() {
        if let data = try? JSONEncoder().encode(savedRecipes) {
            UserDefaults.standard.set(data, forKey: storageKey(for: activeUserID))
        }
        if let deletedData = try? JSONEncoder().encode(Array(deletedSavedRecipeIDs)) {
            UserDefaults.standard.set(deletedData, forKey: deletedStorageKey(for: activeUserID))
        }
    }

    private func load(for userID: String?) {
        let defaults = UserDefaults.standard
        let primaryKey = storageKey(for: userID)
        let deletedKey = deletedStorageKey(for: userID)
        let fallbackKey = userID == nil ? legacyKey : nil

        let data = defaults.data(forKey: primaryKey)
            ?? fallbackKey.flatMap { defaults.data(forKey: $0) }
        let deletedData = defaults.data(forKey: deletedKey)

        guard let data,
              let decoded = try? JSONDecoder().decode([DiscoverRecipeCardData].self, from: data)
        else {
            savedRecipes = []
            deletedSavedRecipeIDs = loadDeletedRecipeIDs(from: deletedData)
            return
        }

        deletedSavedRecipeIDs = loadDeletedRecipeIDs(from: deletedData)
        savedRecipes = deduplicated(decoded.filter { !deletedSavedRecipeIDs.contains($0.id) })

        if defaults.data(forKey: primaryKey) == nil {
            defaults.set(data, forKey: primaryKey)
        }
    }

    private func storageKey(for userID: String?) -> String {
        "\(keyPrefix)-\(userID ?? "guest")"
    }

    private func deletedStorageKey(for userID: String?) -> String {
        "\(deletedKeyPrefix)-\(userID ?? "guest")"
    }

    private func loadDeletedRecipeIDs(from data: Data?) -> Set<String> {
        guard let data,
              let decoded = try? JSONDecoder().decode([String].self, from: data) else {
            return []
        }
        return Set(decoded)
    }

    private func merge(local: [DiscoverRecipeCardData], remote: [DiscoverRecipeCardData]) -> [DiscoverRecipeCardData] {
        // Prefer the server's newest ordering first, then keep any local-only saves.
        let filteredRemote = remote.filter { !deletedSavedRecipeIDs.contains($0.id) }
        return deduplicated(filteredRemote + local)
    }

    private func deduplicated(_ recipes: [DiscoverRecipeCardData]) -> [DiscoverRecipeCardData] {
        var merged: [String: DiscoverRecipeCardData] = [:]
        var orderedIDs: [String] = []

        for recipe in recipes {
            if let existing = merged[recipe.id] {
                merged[recipe.id] = mergeRecipeCards(primary: existing, fallback: recipe)
            } else {
                merged[recipe.id] = recipe
                orderedIDs.append(recipe.id)
            }
        }

        return orderedIDs.compactMap { merged[$0] }
    }

    private func mergeRecipeCards(primary: DiscoverRecipeCardData, fallback: DiscoverRecipeCardData?) -> DiscoverRecipeCardData {
        guard let fallback else { return primary }

        return DiscoverRecipeCardData(
            id: primary.id,
            title: primary.title,
            description: primary.description ?? fallback.description,
            authorName: primary.authorName ?? fallback.authorName,
            authorHandle: primary.authorHandle ?? fallback.authorHandle,
            category: primary.category ?? fallback.category,
            recipeType: primary.recipeType ?? fallback.recipeType,
            discoverBrackets: (primary.discoverBrackets?.isEmpty == false ? primary.discoverBrackets : fallback.discoverBrackets),
            cookTimeText: primary.cookTimeText ?? fallback.cookTimeText,
            cookTimeMinutes: primary.cookTimeMinutes ?? fallback.cookTimeMinutes,
            publishedDate: primary.publishedDate ?? fallback.publishedDate,
            imageURLString: primary.imageURLString ?? fallback.imageURLString,
            heroImageURLString: primary.heroImageURLString ?? fallback.heroImageURLString,
            recipeURLString: primary.recipeURLString ?? fallback.recipeURLString,
            source: primary.source ?? fallback.source
        )
    }

    private func reconcilePendingDeletes(userID: String) async {
        let pending = deletedSavedRecipeIDs
        guard !pending.isEmpty else { return }

        for recipeID in pending {
            do {
                try await SupabaseSavedRecipesService.shared.deleteSavedRecipe(
                    userID: userID,
                    recipeID: recipeID
                )
                deletedSavedRecipeIDs.remove(recipeID)
            } catch {
                // Keep the tombstone locally so the recipe does not resurrect on relaunch.
            }
        }

        persist()
    }
}

private struct MealPlannerShellView: View {
    @Environment(\.scenePhase) private var scenePhase
    @EnvironmentObject private var store: MealPlanningAppStore
    @EnvironmentObject private var realtimeCoordinator: AppRealtimeInvalidationCoordinator
    @ObservedObject private var toastCenter: AppToastCenter
    @StateObject private var sharedImportInbox = SharedRecipeImportInboxStore()
    @StateObject private var recipeImportHistory = RecipeImportHistoryStore()
    @StateObject private var savedStore: SavedRecipesStore
    @StateObject private var discoverRecipesViewModel = DiscoverRecipesViewModel()
    @Namespace private var recipeTransitionNamespace
    @State private var selectedTab: AppTab = .prep
    @State private var discoverSearchText = ""
    @State private var cookbookSearchText = ""
    @State private var presentedRecipe: PresentedRecipeDetail?
    @State private var focusedCartRecipeID: String?
    @State private var requestedCookbookCycleID: String?
    @State private var requestedImportQueueTab: SharedRecipeImportQueueTab?
    @State private var isProcessingSharedImports = false
    @State private var syncedCompletedImportIDs = Set<String>()
    @State private var prewarmedCompletedImportIDs = Set<String>()
    @State private var lastSharedImportRefreshAt = Date.distantPast
    @State private var previousSelectedTab: AppTab = .prep
    @State private var tabTransitionDirection: CGFloat = 1

    private enum SharedImportProcessingScope {
        case queued
        case failed
        case all
    }

    init(toastCenter: AppToastCenter) {
        _toastCenter = ObservedObject(wrappedValue: toastCenter)
        _savedStore = StateObject(wrappedValue: SavedRecipesStore(toastCenter: toastCenter))
    }

    var body: some View {
        GeometryReader { proxy in
            ZStack {
                MainAppBackdrop()

                tabContent
                    .id(selectedTab)
                    .environmentObject(savedStore)
                    .environmentObject(sharedImportInbox)
                    .transition(shellTabTransition)
                    .animation(OunjeMotion.screenSpring, value: selectedTab)
                    .allowsHitTesting(presentedRecipe == nil)
            }
            .background(OunjePalette.background.ignoresSafeArea())
            .overlay(alignment: .top) {
                ZStack {
                    if let toast = toastCenter.toast {
                        AppToastBanner(
                            toast: toast,
                            onTap: toast.destination == nil ? nil : {
                                handleToastTap(toast)
                            }
                        )
                            .id(toast.id)
                            .padding(.horizontal, 16)
                            .padding(.top, 12)
                            .transition(
                                .asymmetric(
                                    insertion: .modifier(
                                        active: DirectionalSurfaceRevealModifier(
                                            xOffset: 0,
                                            yOffset: -18,
                                            scale: 0.96,
                                            blur: 10,
                                            opacity: 0.001
                                        ),
                                        identity: DirectionalSurfaceRevealModifier()
                                    ),
                                    removal: .modifier(
                                        active: DirectionalSurfaceRevealModifier(
                                            xOffset: 0,
                                            yOffset: -12,
                                            scale: 0.985,
                                            blur: 6,
                                            opacity: 0.001
                                        ),
                                        identity: DirectionalSurfaceRevealModifier()
                                    )
                                )
                            )
                            .allowsHitTesting(toast.destination != nil || toast.action != nil)
                    }
                }
                .animation(OunjeMotion.screenSpring, value: toastCenter.toast?.id)
            }
            .safeAreaInset(edge: .bottom, spacing: 0) {
                BottomNavigationDock(
                    selectedTab: $selectedTab,
                    safeAreaBottom: proxy.safeAreaInsets.bottom
                )
                    .transition(.move(edge: .bottom).combined(with: .opacity))
                    .animation(OunjeMotion.tabSpring, value: selectedTab)
            }
            .overlay {
                if let presentedRecipe {
                    RecipeDetailExperienceView(
                        presentedRecipe: presentedRecipe,
                        onOpenCart: {
                            focusedCartRecipeID = presentedRecipe.plannedRecipe?.recipe.id ?? presentedRecipe.recipeCard.id
                            withAnimation(OunjeMotion.heroSpring) {
                                selectedTab = .cart
                                self.presentedRecipe = nil
                            }
                        },
                        toastCenter: toastCenter,
                        onDismiss: dismissPresentedRecipe,
                        transitionNamespace: recipeTransitionNamespace,
                        onOpenToastDestination: openToastDestination
                    )
                    .environmentObject(savedStore)
                    .transition(.opacity)
                    .zIndex(6)
                }
            }
        }
        .ignoresSafeArea(.keyboard, edges: .bottom)
        .task(id: store.authSession?.userID ?? "signed-out") {
            syncedCompletedImportIDs.removeAll()
            prewarmedCompletedImportIDs.removeAll()
            await savedStore.bootstrap(authSession: store.authSession)
        }
        .task(id: "fresh-plan::\(store.authSession?.userID ?? "signed-out")") {
            await store.ensureFreshPlanIfNeeded()
        }
        .task(id: "shared-import::\(store.authSession?.userID ?? "signed-out")") {
            await processPendingSharedImports(scope: .queued)
        }
        .task(id: "shared-import-inbox::\(store.authSession?.userID ?? "signed-out")") {
            await sharedImportInbox.refresh()
        }
        .task(id: "recipe-import-history::\(store.authSession?.userID ?? "signed-out")") {
            await recipeImportHistory.refresh(userID: store.authSession?.userID)
            await sharedImportInbox.reconcileCompletedImports(recipeImportHistory.completedItems)
        }
        .onReceive(NotificationCenter.default.publisher(for: .recipeImportHistoryNeedsRefresh)) { _ in
            Task {
                await refreshSharedImportState()
                lastSharedImportRefreshAt = .now
            }
        }
        .task(id: "shared-import-poll::\(store.authSession?.userID ?? "signed-out")::\(scenePhase == .active ? "active" : "inactive")") {
            guard scenePhase == .active else { return }

            while !Task.isCancelled {
                await sharedImportInbox.refresh()

                let hasQueuedWork = hasQueuedSharedImportWork
                guard hasQueuedWork || hasLiveSharedImportWork else {
                    let idleSleep: UInt64 = realtimeCoordinator.isRunning ? 90_000_000_000 : 30_000_000_000
                    try? await Task.sleep(nanoseconds: idleSleep)
                    continue
                }

                if hasQueuedWork {
                    await processPendingSharedImports(scope: .queued)
                }

                let hasLiveImport = hasLiveSharedImportWork
                let shouldRefreshSharedState = hasLiveImport || Date().timeIntervalSince(lastSharedImportRefreshAt) >= 30
                if shouldRefreshSharedState {
                    await refreshSharedImportState()
                    lastSharedImportRefreshAt = .now
                }

                let sleepSeconds: Double
                if hasLiveImport {
                    sleepSeconds = realtimeCoordinator.isRunning ? 10 : 4
                } else {
                    sleepSeconds = realtimeCoordinator.isRunning ? 30 : 12
                }
                try? await Task.sleep(nanoseconds: UInt64(sleepSeconds * 1_000_000_000))
            }
        }
        .onOpenURL { url in
            guard SharedRecipeImportInbox.isShareImportURL(url) else { return }
            Task {
                await processPendingSharedImports(scope: .queued)
            }
        }
        .onChange(of: scenePhase) { phase in
            guard phase == .active else { return }
            Task {
                await store.runAutomationPassIfNeeded(trigger: "scene_active")
                await sharedImportInbox.refresh()
                if hasQueuedSharedImportWork || hasLiveSharedImportWork {
                    await processPendingSharedImports(scope: .queued)
                    await refreshSharedImportState()
                    lastSharedImportRefreshAt = .now
                }
            }
        }
        .onChange(of: selectedTab) { newTab in
            let previousTab = previousSelectedTab
            tabTransitionDirection = newTab.motionIndex >= previousTab.motionIndex ? 1 : -1
            previousSelectedTab = newTab
            if newTab != .discover {
                discoverSearchText = ""
            }
        }
    }

    private var shellTabTransition: AnyTransition {
        let insertionOffset: CGFloat = tabTransitionDirection >= 0 ? 40 : -40
        let removalOffset: CGFloat = tabTransitionDirection >= 0 ? -18 : 18

        return .asymmetric(
            insertion: .modifier(
                active: DirectionalSurfaceRevealModifier(
                    xOffset: insertionOffset,
                    yOffset: 0,
                    scale: 0.985,
                    blur: 10,
                    opacity: 0.001
                ),
                identity: DirectionalSurfaceRevealModifier()
            ),
            removal: .modifier(
                active: DirectionalSurfaceRevealModifier(
                    xOffset: removalOffset,
                    yOffset: 0,
                    scale: 0.992,
                    blur: 6,
                    opacity: 0.001
                ),
                identity: DirectionalSurfaceRevealModifier()
            )
        )
    }

    @ViewBuilder
    private var tabContent: some View {
        switch selectedTab {
        case .prep:
            PrepTabView(
                selectedTab: $selectedTab,
                requestedCookbookCycleID: $requestedCookbookCycleID,
                recipeTransitionNamespace: recipeTransitionNamespace,
                onSelectRecipe: { plannedRecipe in
                    presentRecipeDetail(PresentedRecipeDetail(plannedRecipe: plannedRecipe))
                }
            )
        case .discover:
            DiscoverTabView(
                selectedTab: $selectedTab,
                searchText: $discoverSearchText,
                recipeTransitionNamespace: recipeTransitionNamespace,
                onSelectRecipe: { recipe in
                    presentRecipeDetail(PresentedRecipeDetail(recipeCard: recipe))
                },
                viewModel: discoverRecipesViewModel
            )
        case .cookbook:
                CookbookTabView(
                    selectedTab: $selectedTab,
                    searchText: $cookbookSearchText,
                    requestedCycleID: $requestedCookbookCycleID,
                    requestedImportQueueTab: $requestedImportQueueTab,
                    recipeTransitionNamespace: recipeTransitionNamespace,
                    sharedImportInbox: sharedImportInbox,
                    recipeImportHistory: recipeImportHistory,
                    toastCenter: toastCenter,
                    onRefreshSharedImports: {
                        Task {
                            await refreshSharedImportState()
                        }
                    },
                    onRetryFailedSharedImports: {
                        Task {
                            await processPendingSharedImports(scope: .failed)
                            await refreshSharedImportState()
                        }
                    },
                    onDeleteFailedSharedImport: { envelopeID in
                        Task {
                            try? SharedRecipeImportInbox.delete(envelopeID: envelopeID)
                            await refreshSharedImportState()
                        }
                    },
                    onSelectRecipe: { recipe in
                        presentRecipeDetail(PresentedRecipeDetail(recipeCard: recipe))
                    }
                )
        case .cart:
            CartTabView(selectedTab: $selectedTab, focusedRecipeID: $focusedCartRecipeID)
        case .profile:
            ProfileTabView()
        }
    }

    @MainActor
    private func refreshSharedImportState() async {
        await sharedImportInbox.refresh()
        await recipeImportHistory.refresh(userID: store.authSession?.userID)
        await sharedImportInbox.reconcileCompletedImports(recipeImportHistory.completedItems)
        await syncCompletedImportsIntoSavedStore()
        await prewarmCompletedImportDetails()
    }

    @MainActor
    private func syncCompletedImportsIntoSavedStore() async {
        for item in recipeImportHistory.completedItems.reversed() {
            guard syncedCompletedImportIDs.insert(item.id).inserted else { continue }
            guard let savedRecipe = item.savedRecipeCard else { continue }
            savedStore.saveImportedRecipe(savedRecipe, showToast: false)
        }
    }

    private func prewarmCompletedImportDetails() async {
        let recipeIDs = recipeImportHistory.completedItems.compactMap { item -> String? in
            guard let id = item.recipeID?.trimmingCharacters(in: .whitespacesAndNewlines), !id.isEmpty else {
                return nil
            }
            return id
        }

        for recipeID in recipeIDs.reversed() {
            guard prewarmedCompletedImportIDs.insert(recipeID).inserted else { continue }
            Task(priority: .utility) {
                _ = try? await RecipeDetailService.shared.fetchRecipeDetail(id: recipeID)
            }
        }
    }

    private func presentRecipeDetail(_ recipe: PresentedRecipeDetail) {
        withAnimation(OunjeMotion.heroSpring) {
            presentedRecipe = recipe
        }
    }

    private func dismissPresentedRecipe() {
        withAnimation(OunjeMotion.heroSpring) {
            presentedRecipe = nil
        }
    }

    private func handleToastTap(_ toast: AppToast) {
        guard let destination = toast.destination else { return }
        toastCenter.dismiss()
        openToastDestination(destination)
    }

    private func openToastDestination(_ destination: AppToastDestination) {
        withAnimation(OunjeMotion.heroSpring) {
            switch destination {
            case .recipe(let recipe):
                selectedTab = .cookbook
                presentedRecipe = PresentedRecipeDetail(recipeCard: recipe)
            case .recipeImportQueue(let tab):
                presentedRecipe = nil
                requestedImportQueueTab = tab
                selectedTab = .cookbook
            case .appTab(let tab):
                presentedRecipe = nil
                selectedTab = tab
            }
        }
    }

    private var hasQueuedSharedImportWork: Bool {
        sharedImportInbox.envelopes.contains { envelope in
            envelope.shouldAutoProcess || envelope.isRetryNeeded
        }
    }

    private var hasLiveSharedImportWork: Bool {
        sharedImportInbox.envelopes.contains { envelope in
            switch envelope.normalizedProcessingState {
            case "queued", "processing", "fetching", "parsing", "normalized":
                return true
            default:
                return false
            }
        }
    }

    @MainActor
    private func processPendingSharedImports(scope: SharedImportProcessingScope = .queued) async {
        guard !isProcessingSharedImports, let userID = store.authSession?.userID else { return }

        let envelopes: [SharedRecipeImportEnvelope]
        do {
            envelopes = try SharedRecipeImportInbox.readAll()
        } catch {
            return
        }

        guard !envelopes.isEmpty else {
            await sharedImportInbox.refresh()
            return
        }
        isProcessingSharedImports = true
        defer { isProcessingSharedImports = false }

        let eligibleEnvelopes = envelopes.filter { envelope in
            switch scope {
            case .queued:
                return envelope.shouldAutoProcess
            case .failed:
                return envelope.isRetryNeeded
            case .all:
                return envelope.shouldAutoProcess || envelope.isRetryNeeded
            }
        }

        guard !eligibleEnvelopes.isEmpty else {
            await sharedImportInbox.refresh()
            return
        }

        for envelope in eligibleEnvelopes {
            do {
                var processingEnvelope = envelope
                let nextAttemptCount = (processingEnvelope.attemptCount ?? 0) + 1
                processingEnvelope = SharedRecipeImportEnvelope(
                    id: processingEnvelope.id,
                    createdAt: processingEnvelope.createdAt,
                    jobID: processingEnvelope.jobID,
                    targetState: processingEnvelope.targetState,
                    sourceText: processingEnvelope.sourceText,
                    sourceURLString: processingEnvelope.sourceURLString,
                    canonicalSourceURLString: processingEnvelope.canonicalSourceURLString,
                    sourceApp: processingEnvelope.sourceApp,
                    attachments: processingEnvelope.attachments,
                    processingState: "processing",
                    attemptCount: nextAttemptCount,
                    lastAttemptAt: Date(),
                    lastError: nil,
                    updatedAt: Date()
                )
                try? SharedRecipeImportInbox.update(processingEnvelope)
                await sharedImportInbox.refresh()

                let response: RecipeImportResponse
                if let existingJobID = envelope.jobID?.trimmingCharacters(in: .whitespacesAndNewlines),
                   !existingJobID.isEmpty,
                   (envelope.attemptCount ?? 0) > 0 {
                    response = try await RecipeImportAPIService.shared.fetchImportJob(jobID: existingJobID)
                } else {
                    let attachments = try await sharedImportAttachmentPayloads(from: envelope.attachments)
                    response = try await RecipeImportAPIService.shared.importRecipe(
                        userID: userID,
                        accessToken: store.authSession?.accessToken,
                        sourceURL: envelope.sourceURLString?.trimmingCharacters(in: .whitespacesAndNewlines),
                        sourceText: envelope.resolvedSourceText,
                        targetState: envelope.targetState,
                        attachments: attachments
                    )
                }

                if let importedRecipe = response.recipe {
                    savedStore.saveImportedRecipe(importedRecipe, showToast: false)
                }
                NotificationCenter.default.post(name: .recipeImportHistoryNeedsRefresh, object: nil)
                let backendProcessingState = response.job.status.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
                let isLiveBackendState = ["queued", "processing", "fetching", "parsing", "normalized"].contains(backendProcessingState)
                let reviewState = response.job.reviewState.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
                let canDisplayImportedRecipe = response.recipe != nil || response.recipeDetail != nil
                let importFailureReason = [
                    response.job.errorMessage,
                    response.job.reviewReason,
                    "Ounje could not extract a displayable recipe from this share."
                ]
                .compactMap { raw -> String? in
                    let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                    return trimmed.isEmpty ? nil : trimmed
                }
                .first
                let shouldFailImport = backendProcessingState == "failed"
                    || (["draft", "needs_review"].contains(reviewState) && !canDisplayImportedRecipe)

                if shouldFailImport {
                    let failedEnvelope = SharedRecipeImportEnvelope(
                        id: envelope.id,
                        createdAt: envelope.createdAt,
                        jobID: response.job.id,
                        targetState: envelope.targetState,
                        sourceText: envelope.sourceText,
                        sourceURLString: envelope.sourceURLString,
                        canonicalSourceURLString: [
                            response.recipeDetail?.originalRecipeURLString,
                            response.recipeDetail?.recipeURLString,
                            response.job.sourceURL
                        ]
                        .compactMap { raw -> String? in
                            let trimmed = raw?.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines) ?? ""
                            return trimmed.isEmpty ? nil : trimmed
                        }
                        .first
                            ?? envelope.canonicalSourceURLString,
                        sourceApp: envelope.sourceApp,
                        attachments: envelope.attachments,
                        processingState: "failed",
                        attemptCount: processingEnvelope.attemptCount,
                        lastAttemptAt: Date(),
                        lastError: importFailureReason,
                        updatedAt: Date()
                    )
                    try? SharedRecipeImportInbox.update(failedEnvelope)
                    toastCenter.show(
                        title: "Couldn’t import share",
                        subtitle: importFailureReason,
                        systemImage: "exclamationmark.circle.fill",
                        destination: .recipeImportQueue(.failed)
                    )
                } else if let detail = response.recipeDetail, envelope.targetState == "prepped" {
                    await store.updateLatestPlan(with: importedRecipePlanModel(from: detail), servings: detail.displayServings)
                    selectedTab = .prep
                    toastCenter.show(
                        title: "Added to next prep",
                        subtitle: detail.title,
                        systemImage: "sparkles",
                        thumbnailURLString: detail.discoverCardImageURLString ?? detail.heroImageURLString ?? detail.imageURL?.absoluteString,
                        destination: .appTab(.prep)
                    )
                    try? SharedRecipeImportInbox.delete(envelopeID: envelope.id)
                } else if isLiveBackendState {
                    let normalizedProcessingState: String = {
                        switch backendProcessingState {
                        case "queued", "processing", "fetching", "parsing", "normalized", "saved":
                            return backendProcessingState
                        default:
                            return "queued"
                        }
                    }()
                    let queuedEnvelope = SharedRecipeImportEnvelope(
                        id: envelope.id,
                        createdAt: envelope.createdAt,
                        jobID: response.job.id,
                        targetState: envelope.targetState,
                        sourceText: envelope.sourceText,
                        sourceURLString: envelope.sourceURLString,
                        canonicalSourceURLString: [
                            response.recipeDetail?.originalRecipeURLString,
                            response.recipeDetail?.recipeURLString,
                            response.job.sourceURL
                        ]
                        .compactMap { raw -> String? in
                            let trimmed = raw?.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines) ?? ""
                            return trimmed.isEmpty ? nil : trimmed
                        }
                        .first
                            ?? envelope.canonicalSourceURLString,
                        sourceApp: envelope.sourceApp,
                        attachments: envelope.attachments,
                        processingState: normalizedProcessingState,
                        attemptCount: processingEnvelope.attemptCount,
                        lastAttemptAt: Date(),
                        lastError: nil,
                        updatedAt: Date()
                    )
                    try? SharedRecipeImportInbox.update(queuedEnvelope)
                    if (envelope.attemptCount ?? 0) <= 1 {
                        toastCenter.show(
                            title: "Import queued",
                            subtitle: envelope.resolvedSourceText.isEmpty ? "Ounje is pulling your recipe in now." : envelope.resolvedSourceText,
                            systemImage: "tray.and.arrow.down.fill",
                            destination: .recipeImportQueue(.queued)
                        )
                    }
                } else if ["draft", "needs_review", "saved"].contains(backendProcessingState) || response.recipe != nil {
                    selectedTab = .cookbook
                    toastCenter.show(
                        title: "Saved",
                        subtitle: response.recipe?.title ?? "Imported recipe",
                        systemImage: "bookmark.fill",
                        thumbnailURLString: response.recipe?.imageURL?.absoluteString,
                        destination: response.recipe.map(AppToastDestination.recipe) ?? .recipeImportQueue(.completed)
                    )
                    try? SharedRecipeImportInbox.delete(envelopeID: envelope.id)
                }

                await sharedImportInbox.refresh()
                NotificationCenter.default.post(name: .recipeImportHistoryNeedsRefresh, object: nil)
            } catch {
                let errorMessage = (error as? RecipeImportServiceError).map {
                    switch $0 {
                    case .invalidRequest:
                        return "Invalid import request."
                    case .invalidResponse:
                        return "Unexpected import response."
                    case .requestFailed(let message):
                        return message
                    }
                } ?? error.localizedDescription
                let failedEnvelope = SharedRecipeImportEnvelope(
                    id: envelope.id,
                    createdAt: envelope.createdAt,
                    jobID: envelope.jobID,
                    targetState: envelope.targetState,
                    sourceText: envelope.sourceText,
                    sourceURLString: envelope.sourceURLString,
                    canonicalSourceURLString: envelope.canonicalSourceURLString,
                    sourceApp: envelope.sourceApp,
                    attachments: envelope.attachments,
                    processingState: "failed",
                    attemptCount: (envelope.attemptCount ?? 0) + 1,
                    lastAttemptAt: Date(),
                    lastError: errorMessage,
                    updatedAt: Date()
                )
                try? SharedRecipeImportInbox.update(failedEnvelope)
                await sharedImportInbox.refresh()
                NotificationCenter.default.post(name: .recipeImportHistoryNeedsRefresh, object: nil)
                toastCenter.show(
                    title: "Couldn’t import share",
                    subtitle: errorMessage,
                    systemImage: "exclamationmark.circle.fill",
                    destination: .recipeImportQueue(.failed)
                )
            }
        }
    }
}

private struct DiscoverTabView: View {
    @EnvironmentObject private var store: MealPlanningAppStore
    @EnvironmentObject private var savedStore: SavedRecipesStore
    @Binding var selectedTab: AppTab
    @Binding var searchText: String
    let recipeTransitionNamespace: Namespace.ID
    let onSelectRecipe: (DiscoverRecipeCardData) -> Void
    @ObservedObject var viewModel: DiscoverRecipesViewModel
    @StateObject private var environmentModel = DiscoverEnvironmentViewModel()
    @State private var hasAppearedOnce = false
    @State private var searchRefreshTask: Task<Void, Never>?
    @State private var isManualRefreshing = false
    @State private var isShowingPullRefreshCue = false
    @State private var hasPresentedPullRefreshCue = false
    @State private var discoverPullDistance: CGFloat = 0
    @State private var discoverPullBaseline: CGFloat?

    private let recipeColumns = [
        GridItem(.flexible(), spacing: 16, alignment: .top),
        GridItem(.flexible(), spacing: 16, alignment: .top)
    ]

    private var filters: [String] {
        viewModel.filters
    }

    private var filteredRecipes: [DiscoverRecipeCardData] {
        viewModel.recipes
    }

    private var greetingLine: String {
        let name = store.profile?.trimmedPreferredName
        if let name, !name.isEmpty {
            return "Welcome back, \(name)."
        }
        return "Welcome back."
    }

    private var dateLine: String {
        Date.now.formatted(.dateTime.weekday(.wide).month(.wide).day())
    }

    private var mealPrompt: String {
        let hour = Calendar.current.component(.hour, from: .now)
        switch hour {
        case 5..<11:
            return "What are we making for breakfast?"
        case 11..<16:
            return "What are we making for lunch?"
        case 16..<22:
            return "What are we making for dinner?"
        default:
            return "What are we prepping next?"
        }
    }

    private var visibleRecipes: [DiscoverRecipeCardData] {
        filteredRecipes
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    var body: some View {
        GeometryReader { proxy in
            VStack(alignment: .leading, spacing: 0) {
                VStack(alignment: .leading, spacing: 20) {
                    VStack(alignment: .leading, spacing: 3) {
                        BiroScriptDisplayText("Discover", size: 31, color: OunjePalette.primaryText)
                        Text("Find your next meal")
                            .font(.system(size: 14, weight: .medium))
                            .foregroundStyle(OunjePalette.secondaryText)
                    }

                    CompactDiscoverSearchField(
                        text: $searchText,
                        isLoading: viewModel.isLoading && isSearching,
                        isRefreshing: viewModel.isTransitioningFeed && !visibleRecipes.isEmpty
                    )

                    ScrollView(.horizontal, showsIndicators: false) {
                        HStack(alignment: .firstTextBaseline, spacing: 26) {
                            ForEach(filters, id: \.self) { filter in
                                DiscoverPresetTextButton(
                                    title: filter,
                                    isSelected: viewModel.selectedFilter == filter
                                ) {
                                    withAnimation(.spring(response: 0.3, dampingFraction: 0.84)) {
                                        viewModel.selectFilter(filter, isSearching: isSearching)
                                    }
                                }
                            }
                        }
                        .padding(.trailing, 10)
                        .padding(.top, 2)
                        .padding(.bottom, 4)
                    }

                }
                .padding(.horizontal, OunjeLayout.screenHorizontalPadding)
                .padding(.top, 14)
                .padding(.bottom, 10)

                ScrollView {
                    VStack(alignment: .leading, spacing: 20) {
                        GeometryReader { geometry in
                            Color.clear.preference(
                                key: PullStretchRefreshOffsetPreferenceKey.self,
                                value: geometry.frame(in: .named("discover-feed-scroll")).minY
                            )
                        }
                        .frame(height: 0)

                        if shouldShowDiscoverPullIndicator {
                            PullStretchRefreshIndicator(
                                phase: discoverPullRefreshPhase,
                                pullDistance: discoverPullDistance
                            )
                            .transition(.opacity.combined(with: .move(edge: .top)))
                        }

                        discoverRecipeFeedContent
                    }
                    .padding(.horizontal, OunjeLayout.screenHorizontalPadding)
                    .padding(.top, 2)
                    .padding(.bottom, 140)
                }
                .coordinateSpace(name: "discover-feed-scroll")
                .scrollIndicators(.hidden)
                .onPreferenceChange(PullStretchRefreshOffsetPreferenceKey.self) { value in
                    updateDiscoverPullDistance(value)
                }
                .refreshable {
                    await refreshDiscoverFromPull()
                }
            }
            .frame(width: proxy.size.width, height: proxy.size.height, alignment: .top)
        }
        .task(id: discoverFeedKey) {
            let initialContext = environmentModel.feedContext
            viewModel.updateFeedbackRevision(discoverFeedbackRevision)
            async let environmentRefresh: Void = environmentModel.refresh(profile: store.profile)
            await viewModel.loadIfNeeded(profile: store.profile, query: searchText, feedContext: initialContext)
            await environmentRefresh
            let refreshedContext = environmentModel.feedContext
            guard refreshedContext.cacheKey != initialContext.cacheKey else { return }
            guard viewModel.recipes.isEmpty || viewModel.errorMessage != nil else { return }
            await viewModel.forceReload(profile: store.profile, query: searchText, feedContext: refreshedContext)
        }
        .onChange(of: searchText) { newValue in
            searchRefreshTask?.cancel()

            let normalized = newValue.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !normalized.isEmpty else {
                Task {
                    await viewModel.loadIfNeeded(profile: store.profile, query: "", feedContext: environmentModel.feedContext)
                }
                return
            }

            if viewModel.selectedFilter != "All" {
                viewModel.selectFilter("All", isSearching: true)
            }
            viewModel.resetFeedPagination()
            viewModel.prepareForQueryRefresh()
            searchRefreshTask = Task {
                try? await Task.sleep(nanoseconds: 90_000_000)
                guard !Task.isCancelled else { return }
                await viewModel.refresh(profile: store.profile, query: normalized, feedContext: environmentModel.feedContext, offset: 0)
            }
        }
        .onAppear {
            viewModel.clearTransientError()
            viewModel.updateFeedbackRevision(discoverFeedbackRevision)
            presentPullRefreshCueIfNeeded()
            if normalizedSearchText.isEmpty {
                viewModel.selectedFilter = "All"
            }

            guard normalizedSearchText.isEmpty else { return }
            guard hasAppearedOnce else {
                hasAppearedOnce = true
                return
            }
            Task {
                if viewModel.recipes.isEmpty || viewModel.errorMessage != nil {
                    await viewModel.loadIfNeeded(profile: store.profile, query: searchText, feedContext: environmentModel.feedContext)
                }
            }
        }
    }

    @ViewBuilder
    private var discoverRecipeFeedContent: some View {
        if let errorMessage = viewModel.errorMessage,
           viewModel.hasResolvedInitialLoad,
           !viewModel.isLoading,
           !visibleRecipes.isEmpty {
            VStack(alignment: .leading, spacing: 8) {
                Text("Recipe feed unavailable")
                    .biroHeaderFont(18)
                    .foregroundStyle(OunjePalette.primaryText)
                Text(errorMessage)
                    .font(.system(size: 14, weight: .medium))
                    .foregroundStyle(OunjePalette.secondaryText)
            }
            .frame(maxWidth: .infinity, alignment: .leading)
            .padding(.vertical, 6)
        } else if !viewModel.hasResolvedInitialLoad
                    || (visibleRecipes.isEmpty && (viewModel.isLoading || viewModel.isTransitioningFeed))
                    || (viewModel.errorMessage != nil && visibleRecipes.isEmpty) {
            LazyVGrid(columns: recipeColumns, spacing: 14) {
                ForEach(0..<6, id: \.self) { _ in
                    DiscoverRecipeCardLoadingPlaceholder()
                }
            }
        } else if visibleRecipes.isEmpty {
            RecipesEmptyState(
                title: "No recipes matched",
                detail: "Try a different keyword or category.",
                symbolName: "fork.knife",
                assetName: "CookbookEmptyIllustrationLight"
            )
        } else {
            if viewModel.isTransitioningFeed && !visibleRecipes.isEmpty {
                DiscoverInlineLoadingState(message: "Refreshing your feed")
            }

            LazyVGrid(columns: recipeColumns, spacing: 16) {
                ForEach(visibleRecipes) { recipe in
                    DiscoverRemoteRecipeCard(
                        recipe: recipe,
                        transitionNamespace: recipeTransitionNamespace
                    ) {
                        onSelectRecipe(recipe)
                    }
                    .onAppear {
                        guard shouldPrefetch(after: recipe) else { return }
                        Task {
                            await viewModel.loadMoreIfNeeded(profile: store.profile, query: searchText, feedContext: environmentModel.feedContext)
                        }
                    }
                }
            }
            if viewModel.isFetchingMore {
                LazyVGrid(columns: recipeColumns, spacing: 14) {
                    ForEach(0..<2, id: \.self) { _ in
                        DiscoverRecipeCardLoadingPlaceholder()
                    }
                }
                .padding(.top, 2)
            }

            Color.clear
                .frame(height: 1)
                .onAppear {
                    guard viewModel.hasMoreRecipes, !viewModel.isLoading, !viewModel.isFetchingMore else { return }
                    Task {
                        await viewModel.loadMoreIfNeeded(profile: store.profile, query: searchText, feedContext: environmentModel.feedContext)
                    }
                }
        }
    }

    private var discoverFeedKey: String {
        let cuisines = store.profile?.preferredCuisines.map(\.rawValue).joined(separator: ",") ?? ""
        let foods = store.profile?.favoriteFoods.joined(separator: ",") ?? ""
        let flavors = store.profile?.favoriteFlavors.joined(separator: ",") ?? ""
        let dietary = store.profile?.dietaryPatterns.joined(separator: ",") ?? ""
        let goals = store.profile?.mealPrepGoals.joined(separator: ",") ?? ""
        let address = store.profile?.deliveryAddress
        let environmentKey = [
            address?.city ?? "",
            address?.region ?? "",
            address?.postalCode ?? ""
        ].joined(separator: "|")
        return "\(cuisines)|\(foods)|\(flavors)|\(dietary)|\(goals)|\(viewModel.selectedFilter)|\(normalizedSearchText)|\(environmentKey)|feedback:\(discoverFeedbackRevision)"
    }

    private var discoverFeedbackRevision: Int {
        savedStore.savedRecipes.count / 3
    }

    private var shouldShowDiscoverPullIndicator: Bool {
        isShowingPullRefreshCue
            || isManualRefreshing
            || (viewModel.isTransitioningFeed && !visibleRecipes.isEmpty)
            || discoverPullDistance > 6
    }

    private var discoverPullRefreshPhase: PullStretchRefreshPhase {
        if isManualRefreshing || (viewModel.isTransitioningFeed && !visibleRecipes.isEmpty) {
            return .refreshing
        }
        if discoverPullDistance >= 62 {
            return .release
        }
        if discoverPullDistance > 6 {
            return .pulling
        }
        return .hint
    }

    private func updateDiscoverPullDistance(_ offset: CGFloat) {
        if discoverPullBaseline == nil {
            discoverPullBaseline = offset
        }

        let baseline = discoverPullBaseline ?? offset
        let distance = max(0, offset - baseline)
        discoverPullDistance = distance > 1 ? distance : 0
    }

    private func presentPullRefreshCueIfNeeded() {
        guard !hasPresentedPullRefreshCue, normalizedSearchText.isEmpty else { return }
        hasPresentedPullRefreshCue = true
        Task { @MainActor in
            withAnimation(.easeOut(duration: 0.22)) {
                isShowingPullRefreshCue = true
            }
            try? await Task.sleep(nanoseconds: 2_200_000_000)
            withAnimation(.easeInOut(duration: 0.24)) {
                isShowingPullRefreshCue = false
            }
        }
    }

    private func refreshDiscoverFromPull() async {
        guard !isManualRefreshing else { return }
        isManualRefreshing = true
        defer { isManualRefreshing = false }
        viewModel.updateFeedbackRevision(discoverFeedbackRevision)
        await viewModel.forceReload(
            profile: store.profile,
            query: searchText,
            feedContext: environmentModel.feedContext,
            rotateBaseFeed: normalizedSearchText.isEmpty,
            forceNetwork: true
        )
    }

    private func shouldPrefetch(after recipe: DiscoverRecipeCardData) -> Bool {
        guard let currentIndex = visibleRecipes.firstIndex(where: { $0.id == recipe.id }) else { return false }
        let thresholdIndex = max(visibleRecipes.count - 4, 0)
        return currentIndex >= thresholdIndex
    }
}

private struct DiscoverInlineLoadingState: View {
    var message: String = "Refreshing"

    var body: some View {
        HStack(spacing: 10) {
            DiscoverRiveLoader(size: 18)

            Text(message)
                .font(.system(size: 12, weight: .semibold))
                .foregroundStyle(OunjePalette.secondaryText)
        }
        .padding(.horizontal, 10)
        .padding(.vertical, 6)
        .background(
            Capsule(style: .continuous)
                .fill(OunjePalette.surface.opacity(0.82))
                .overlay(
                    Capsule(style: .continuous)
                        .stroke(OunjePalette.stroke.opacity(0.8), lineWidth: 1)
                )
        )
    }
}

private enum PullStretchRefreshPhase: Equatable {
    case hint
    case pulling
    case release
    case refreshing
    case complete
}

private struct PullStretchRefreshOffsetPreferenceKey: PreferenceKey {
    static var defaultValue: CGFloat = 0

    static func reduce(value: inout CGFloat, nextValue: () -> CGFloat) {
        value = nextValue()
    }
}

private struct PullStretchRefreshIndicator: View {
    let phase: PullStretchRefreshPhase
    var pullDistance: CGFloat = 0
    @State private var isAnimating = false
    @Environment(\.accessibilityReduceMotion) private var reduceMotion

    private var pullProgress: CGFloat {
        min(max(pullDistance / 62, 0), 1)
    }

    private var title: String {
        switch phase {
        case .hint:
            return "Pull here for fresh ideas"
        case .pulling:
            return "Keep pulling"
        case .release:
            return "Release to refresh"
        case .refreshing:
            return "Refreshing ideas"
        case .complete:
            return "Fresh ideas ready"
        }
    }

    var body: some View {
        HStack(spacing: 9) {
            if phase == .refreshing {
                DiscoverRiveLoader(size: 18)
            } else if phase == .complete {
                Image(systemName: "checkmark")
                    .font(.system(size: 12, weight: .bold))
            } else {
                Image(systemName: "arrow.down")
                    .font(.system(size: 12, weight: .bold))
                    .rotationEffect(.degrees(phase == .release ? 180 : 0))
                    .offset(y: reduceMotion ? 0 : (isAnimating ? 3 : -2))
            }

            Text(title)
                .font(.system(size: 12, weight: .semibold))
                .lineLimit(1)
                .minimumScaleFactor(0.82)
        }
        .foregroundStyle(OunjePalette.softCream.opacity(phase == .refreshing ? 0.95 : 0.76))
        .padding(.vertical, 4)
        .scaleEffect(
            x: reduceMotion ? 1 : 1 + (pullProgress * 0.06),
            y: reduceMotion ? 1 : 1 + (pullProgress * 0.16),
            anchor: .center
        )
        .frame(maxWidth: .infinity, alignment: .center)
        .animation(.spring(response: 0.28, dampingFraction: 0.82), value: phase)
        .animation(.spring(response: 0.24, dampingFraction: 0.78), value: pullProgress)
        .accessibilityLabel(phase == .refreshing ? "Refreshing Discover recipes" : "Pull down to refresh Discover recipes")
        .onAppear {
            guard !reduceMotion else { return }
            withAnimation(.easeInOut(duration: 0.62).repeatForever(autoreverses: true)) {
                isAnimating = true
            }
        }
    }
}

private struct HoppingCartIcon: View {
    let isActive: Bool
    var color: Color = Color.white.opacity(0.86)
    var size: CGFloat = 16
    @Environment(\.accessibilityReduceMotion) private var reduceMotion

    var body: some View {
        Group {
            if isActive && !reduceMotion {
                TimelineView(.animation) { context in
                    let time = context.date.timeIntervalSinceReferenceDate
                    let hop = -CGFloat(max(0, sin(time * 5.8))) * 5
                    let squash = 1 + CGFloat(max(0, sin(time * 5.8))) * 0.04

                    Image(systemName: "cart.fill")
                        .font(.system(size: size, weight: .semibold))
                        .foregroundStyle(color)
                        .offset(y: -2 + hop)
                        .scaleEffect(x: squash, y: 1 - ((squash - 1) * 0.5), anchor: .bottom)
                }
            } else {
                Image(systemName: "cart.fill")
                    .font(.system(size: size, weight: .semibold))
                    .foregroundStyle(color)
                    .offset(y: -2)
            }
        }
        .accessibilityHidden(true)
    }
}

private struct PulsingTrayIcon: View {
    let count: Int
    let isPulsing: Bool
    @State private var pulse = false
    @Environment(\.accessibilityReduceMotion) private var reduceMotion

    var body: some View {
        ZStack(alignment: .topTrailing) {
            ZStack {
                if isPulsing && !reduceMotion {
                    RoundedRectangle(cornerRadius: 15, style: .continuous)
                        .stroke(OunjePalette.accent.opacity(pulse ? 0.14 : 0.42), lineWidth: 1.4)
                        .frame(width: 44, height: 44)
                        .scaleEffect(pulse ? 1.16 : 0.96)
                }

                Image(systemName: "tray.full")
                    .font(.system(size: 15, weight: .bold))
                    .foregroundStyle(OunjePalette.primaryText)
                    .frame(width: 42, height: 42)
                    .background(
                        RoundedRectangle(cornerRadius: 14, style: .continuous)
                            .fill(OunjePalette.surface)
                            .overlay(
                                RoundedRectangle(cornerRadius: 14, style: .continuous)
                                    .stroke(OunjePalette.stroke, lineWidth: 1)
                            )
                    )
                    .scaleEffect(isPulsing && !reduceMotion && pulse ? 1.04 : 1)
            }

            if count > 0 {
                Text("\(count)")
                    .font(.system(size: 10, weight: .bold))
                    .foregroundStyle(OunjePalette.background)
                    .padding(.horizontal, 5)
                    .padding(.vertical, 2)
                    .background(
                        Capsule(style: .continuous)
                            .fill(OunjePalette.accent)
                    )
                    .offset(x: 4, y: -4)
            }
        }
        .onAppear { updatePulseAnimation() }
        .onChange(of: isPulsing) { _ in
            updatePulseAnimation()
        }
    }

    private func updatePulseAnimation() {
        guard isPulsing, !reduceMotion else {
            pulse = false
            return
        }

        withAnimation(.easeInOut(duration: 0.92).repeatForever(autoreverses: true)) {
            pulse = true
        }
    }
}

private struct MotionEmptyIllustration: View {
    let assetName: String
    var height: CGFloat
    var maxWidth: CGFloat? = nil
    var alignment: Alignment = .center
    @State private var floats = false
    @State private var shine = false
    @Environment(\.accessibilityReduceMotion) private var reduceMotion

    var body: some View {
        Image(assetName)
            .renderingMode(.original)
            .resizable()
            .interpolation(.high)
            .scaledToFit()
            .frame(height: height)
            .frame(maxWidth: maxWidth, alignment: alignment)
            .frame(maxWidth: .infinity, alignment: alignment)
            .opacity(0.92)
            .offset(y: reduceMotion ? 0 : (floats ? -4 : 3))
            .scaleEffect(reduceMotion ? 1 : (floats ? 1.012 : 0.992))
            .overlay {
                if !reduceMotion {
                    LinearGradient(
                        colors: [
                            .clear,
                            .white.opacity(0.24),
                            .clear
                        ],
                        startPoint: .top,
                        endPoint: .bottom
                    )
                    .frame(width: max(38, height * 0.34), height: height * 1.45)
                    .rotationEffect(.degrees(18))
                    .offset(x: shine ? height * 1.85 : -height * 1.85)
                    .blendMode(.screen)
                    .opacity(0.7)
                    .allowsHitTesting(false)
                }
            }
            .clipped()
            .accessibilityHidden(true)
            .onAppear {
                guard !reduceMotion else { return }
                withAnimation(.easeInOut(duration: 1.45).repeatForever(autoreverses: true)) {
                    floats = true
                }
                withAnimation(.linear(duration: 2.1).repeatForever(autoreverses: false)) {
                    shine = true
                }
            }
    }
}

private struct StaggeredRevealModifier: ViewModifier {
    let isVisible: Bool
    var delay: Double = 0
    var xOffset: CGFloat = 0
    var yOffset: CGFloat = 16
    @Environment(\.accessibilityReduceMotion) private var reduceMotion

    func body(content: Content) -> some View {
        content
            .opacity(isVisible ? 1 : 0)
            .offset(
                x: reduceMotion ? 0 : (isVisible ? 0 : xOffset),
                y: reduceMotion ? 0 : (isVisible ? 0 : yOffset)
            )
            .scaleEffect(reduceMotion ? 1 : (isVisible ? 1 : 0.985))
            .animation(
                .spring(response: 0.38, dampingFraction: 0.86).delay(delay),
                value: isVisible
            )
    }
}

private enum PurchaseCTAVisualState: Equatable {
    case idle
    case processing
    case success
    case failed
}

private struct PurchasingCTAButton: View {
    let title: String
    let state: PurchaseCTAVisualState
    var height: CGFloat = 44
    var isDisabled: Bool = false
    let action: () -> Void

    @GestureState private var isPressed = false
    @Environment(\.accessibilityReduceMotion) private var reduceMotion

    var body: some View {
        Button(action: action) {
            TimelineView(.animation) { context in
                let progress = fillProgress(at: context.date)

                ZStack(alignment: .leading) {
                    RoundedRectangle(cornerRadius: 8, style: .continuous)
                        .fill(Color(hex: "17191F"))

                    if progress > 0 {
                        RoundedRectangle(cornerRadius: 8, style: .continuous)
                            .fill(OunjePalette.accent.opacity(state == .failed ? 0.34 : 0.82))
                            .frame(maxWidth: .infinity)
                            .scaleEffect(x: progress, y: 1, anchor: .leading)
                    }

                    HStack(spacing: 9) {
                        Spacer(minLength: 0)

                        if state == .success {
                            Image(systemName: "checkmark")
                                .font(.system(size: 13, weight: .bold))
                        } else if state == .failed {
                            Image(systemName: "exclamationmark")
                                .font(.system(size: 13, weight: .bold))
                        }

                        Text(state == .success ? "All set" : title)
                            .font(.system(size: 11, weight: .bold, design: .rounded))
                            .foregroundStyle(.white)
                            .textCase(.uppercase)
                            .lineLimit(1)
                            .minimumScaleFactor(0.82)

                        Spacer(minLength: 0)
                    }
                    .foregroundStyle(.white)
                }
                .frame(maxWidth: .infinity)
                .frame(height: height)
            }
        }
        .buttonStyle(.plain)
        .disabled(isDisabled || state == .processing)
        .scaleEffect(!reduceMotion && isPressed ? 0.975 : 1)
        .simultaneousGesture(
            DragGesture(minimumDistance: 0)
                .updating($isPressed) { _, state, _ in
                    state = true
                }
        )
        .animation(.spring(response: 0.2, dampingFraction: 0.82), value: isPressed)
        .accessibilityLabel(title)
    }

    private func fillProgress(at date: Date) -> CGFloat {
        switch state {
        case .idle:
            return 0
        case .processing:
            guard !reduceMotion else { return 0.52 }
            let wave = (sin(date.timeIntervalSinceReferenceDate * 2.3) + 1) / 2
            return 0.22 + CGFloat(wave) * 0.64
        case .success:
            return 1
        case .failed:
            return 1
        }
    }
}

