private enum InstacartRunMatchTone {
    case exact
    case partial
    case mismatch

    var tint: Color {
        switch self {
        case .exact:
            return Color(red: 0.19, green: 0.72, blue: 0.42)
        case .partial:
            return Color(red: 0.95, green: 0.69, blue: 0.16)
        case .mismatch:
            return Color(red: 0.94, green: 0.28, blue: 0.31)
        }
    }

    var accessibilityLabel: String {
        switch self {
        case .exact:
            return "Exact match"
        case .partial:
            return "Partial match"
        case .mismatch:
            return "Mismatch"
        }
    }
}

private func cleanedCandidateTitle(_ raw: String?) -> String? {
    guard var value = raw?.trimmingCharacters(in: .whitespacesAndNewlines), !value.isEmpty else {
        return nil
    }

    value = value.replacingOccurrences(
        of: #"(?i)^current price:\s*\$?[0-9.,]+(?:\$?[0-9.,]+)?\s*"#,
        with: "",
        options: .regularExpression
    )
    value = value.replacingOccurrences(
        of: #"(?i)\b(many in stock|low in stock|out of stock|add)\b"#,
        with: "",
        options: .regularExpression
    )
    value = value.replacingOccurrences(of: #"\s{2,}"#, with: " ", options: .regularExpression)
    value = value.trimmingCharacters(in: .whitespacesAndNewlines)
    return value.isEmpty ? nil : value
}

private func conciseInstacartCandidateTitle(_ values: String?...) -> String? {
    for raw in values {
        if let title = cleanedInstacartDisplayText(raw) {
            return title
        }
    }
    return nil
}

private func instacartMappedProductTitle(_ values: String?...) -> String? {
    for raw in values {
        guard let title = cleanedInstacartDisplayText(raw) else { continue }
        let lower = title.lowercased()
        if lower.contains("instacart item") || lower == "current price" || lower == "matched item" || lower == "store choice" { continue }
        if lower.hasPrefix("no frills") || lower.hasPrefix("food basics") || lower.hasPrefix("metro") { continue }
        return title
    }

    return nil
}

private func cleanedInstacartDisplayText(_ raw: String?) -> String? {
    guard var value = raw?.trimmingCharacters(in: .whitespacesAndNewlines), !value.isEmpty else {
        return nil
    }

    value = value.replacingOccurrences(of: "\u{00a0}", with: " ")
    let lines = value
        .components(separatedBy: .newlines)
        .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        .filter { !$0.isEmpty }

    if lines.count > 1 {
        for line in lines {
            if let title = cleanedInstacartDisplayText(line) {
                return title
            }
        }
    }

    let lower = value.lowercased()
    let cutMarkers = [
        "current price:",
        "many in stock",
        "low in stock",
        "out of stock",
        "best seller",
        "top pick",
        "pickup by",
        "delivery by"
    ]
    for marker in cutMarkers {
        if let range = lower.range(of: marker) {
            value = String(value[..<range.lowerBound])
            break
        }
    }

    value = value.replacingOccurrences(of: #"(?i)^(best seller|top pick)\s*"#, with: "", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)^store choice\s*"#, with: "", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)\b(add|choose)\b.*$"#, with: "", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)current price:\s*"#, with: "", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)\s*\$[0-9][0-9,]*(?:\.[0-9]{2})?.*$"#, with: "", options: .regularExpression)
    value = value.replacingOccurrences(of: #"\s{2,}"#, with: " ", options: .regularExpression)
    value = value.trimmingCharacters(in: .whitespacesAndNewlines)

    guard !value.isEmpty else { return nil }
    let lowerValue = value.lowercased()
    if lowerValue == "instacart item" || lowerValue == "current price" || lowerValue == "store choice" {
        return nil
    }
    if value.rangeOfCharacter(from: .letters) == nil {
        return nil
    }

    if value.count > 62, let lastSpace = value[..<value.index(value.startIndex, offsetBy: 62)].lastIndex(of: " ") {
        value = String(value[..<lastSpace])
    } else if value.count > 62 {
        value = String(value.prefix(62))
    }

    return value.trimmingCharacters(in: .whitespacesAndNewlines)
}

private func cleanedInstacartFailureReasonText(_ raw: String?) -> String? {
    guard var value = raw?.trimmingCharacters(in: .whitespacesAndNewlines), !value.isEmpty else {
        return nil
    }

    value = value.replacingOccurrences(of: "\u{00a0}", with: " ")
    value = value.replacingOccurrences(of: ";", with: " • ")
    value = value.replacingOccurrences(of: "_", with: " ")
    value = value.replacingOccurrences(of: #"(?i)\bfamily guard\b"#, with: "wrong product family", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)\bdescriptor guard\b"#, with: "wrong product details", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)\bquantity guard\b"#, with: "package size mismatch", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)\bheuristic reject low confidence\b"#, with: "match confidence was too weak", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)\bllm exhausted candidate windows\b"#, with: "the visible results never showed a safe match", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)\bcandidate click not found\b"#, with: "Instacart did not expose a usable add action", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)\bcart count not verified\b"#, with: "the product could not be verified in the cart", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)\bpackage too small\b"#, with: "package size was too small", options: .regularExpression)
    value = value.replacingOccurrences(of: #"\s+"#, with: " ", options: .regularExpression)
    value = value.trimmingCharacters(in: .whitespacesAndNewlines)

    if value.count > 120, let lastSpace = value[..<value.index(value.startIndex, offsetBy: 120)].lastIndex(of: " ") {
        value = String(value[..<lastSpace])
    } else if value.count > 120 {
        value = String(value.prefix(120))
    }

    return value.isEmpty ? nil : value
}

private func conciseInstacartPriceText(_ raw: String?) -> String? {
    guard var value = raw?.trimmingCharacters(in: .whitespacesAndNewlines), !value.isEmpty else {
        return nil
    }

    value = value.replacingOccurrences(of: "\u{00a0}", with: " ")
    value = value.replacingOccurrences(of: #"(?i)^current price:\s*"#, with: "", options: .regularExpression)
    value = value.replacingOccurrences(of: #"(?i)^price:\s*"#, with: "", options: .regularExpression)
    value = value.replacingOccurrences(of: #"\s{2,}"#, with: " ", options: .regularExpression)

    if let match = value.range(of: #"\$[0-9][0-9,]*(?:\.[0-9]{2})?"#, options: .regularExpression) {
        return String(value[match]).trimmingCharacters(in: .whitespacesAndNewlines)
    }

    value = value.trimmingCharacters(in: .whitespacesAndNewlines)
    return value.isEmpty ? nil : value
}

private struct SharedRecipeImportQueueRow: View {
    let item: SharedRecipeImportEnvelope
    let onDelete: (() -> Void)?

    private var titleText: String {
        let source = item.sourceURLString?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let source, !source.isEmpty {
            return source
        }

        let sourceText = item.sourceText?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        if !sourceText.isEmpty {
            return sourceText.components(separatedBy: .newlines).first ?? sourceText
        }

        if let app = item.sourceApp?.trimmingCharacters(in: .whitespacesAndNewlines), !app.isEmpty {
            return app
        }

        return "Imported recipe"
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 10) {
            HStack(alignment: .top, spacing: 12) {
                ZStack {
                    RoundedRectangle(cornerRadius: 14, style: .continuous)
                        .fill(OunjePalette.surface)
                        .frame(width: 42, height: 42)

                    Image(systemName: item.isRetryNeeded ? "exclamationmark.triangle.fill" : "tray.full.fill")
                        .font(.system(size: 14, weight: .bold))
                        .foregroundStyle(item.isRetryNeeded ? Color.orange : OunjePalette.primaryText)
                }

                VStack(alignment: .leading, spacing: 4) {
                    Text(titleText)
                        .font(.system(size: 16, weight: .semibold))
                        .foregroundStyle(OunjePalette.primaryText)
                        .lineLimit(2)
                    Text(item.queueStatusLabel)
                        .font(.system(size: 12, weight: .semibold))
                        .foregroundStyle(item.isRetryNeeded ? Color.orange : OunjePalette.secondaryText)
                }

                Spacer(minLength: 0)

                if item.isRetryNeeded, let onDelete {
                    Button(role: .destructive, action: onDelete) {
                        Image(systemName: "trash")
                            .font(.system(size: 13, weight: .bold))
                            .foregroundStyle(Color.red)
                            .frame(width: 30, height: 30)
                            .background(
                                RoundedRectangle(cornerRadius: 9, style: .continuous)
                                    .fill(Color.red.opacity(0.12))
                            )
                    }
                    .buttonStyle(.plain)
                    .accessibilityLabel("Delete failed import")
                }
            }

            if let error = item.lastError, !error.isEmpty {
                Text(error)
                    .font(.system(size: 13, weight: .medium))
                    .foregroundStyle(OunjePalette.secondaryText)
                    .fixedSize(horizontal: false, vertical: true)
            }

            HStack(spacing: 8) {
                if let attemptCount = item.attemptCount {
                    Text("Attempts: \(attemptCount)")
                }
                if let attemptAt = item.lastAttemptAt {
                    Text(attemptAt.formatted(.relative(presentation: .named)))
                } else {
                    Text(item.createdAt.formatted(.relative(presentation: .named)))
                }
            }
            .font(.system(size: 11, weight: .medium))
            .foregroundStyle(OunjePalette.secondaryText)
        }
        .padding(16)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(
            RoundedRectangle(cornerRadius: 20, style: .continuous)
                .fill(OunjePalette.surface.opacity(0.94))
                .overlay(
                    RoundedRectangle(cornerRadius: 20, style: .continuous)
                        .stroke(OunjePalette.stroke, lineWidth: 1)
                )
        )
    }
}

private struct RecipeImportCompletedRow: View {
    let item: RecipeImportCompletedItem
    let onOpenRecipe: ((DiscoverRecipeCardData) -> Void)?

    private var relativeTimestamp: String? {
        let formatter = ISO8601DateFormatter()
        if let completedAt = item.completedAt,
           let date = formatter.date(from: completedAt) {
            return date.formatted(.relative(presentation: .named))
        }
        if let createdAt = item.createdAt,
           let date = formatter.date(from: createdAt) {
            return date.formatted(.relative(presentation: .named))
        }
        return nil
    }

    private var sourceLine: String {
        let parts = [item.source, item.cookTimeText]
            .compactMap { raw -> String? in
                guard let raw else { return nil }
                let trimmed = raw.trimmingCharacters(in: .whitespacesAndNewlines)
                return trimmed.isEmpty ? nil : trimmed
            }
        return parts.isEmpty ? "Imported recipe" : parts.joined(separator: " • ")
    }

    var body: some View {
        HStack(alignment: .top, spacing: 12) {
            Group {
                if let raw = item.imageURL?.trimmingCharacters(in: .whitespacesAndNewlines),
                   let url = URL(string: raw),
                   !raw.isEmpty {
                    AsyncImage(url: url) { phase in
                        switch phase {
                        case .success(let image):
                            image
                                .resizable()
                                .scaledToFill()
                        default:
                            completedFallbackIcon
                        }
                    }
                } else {
                    completedFallbackIcon
                }
            }
            .frame(width: 46, height: 46)
            .clipShape(RoundedRectangle(cornerRadius: 14, style: .continuous))

            VStack(alignment: .leading, spacing: 5) {
                Text(item.title)
                    .font(.system(size: 16, weight: .semibold))
                    .foregroundStyle(OunjePalette.primaryText)
                    .lineLimit(2)

                Text(sourceLine)
                    .font(.system(size: 12, weight: .semibold))
                    .foregroundStyle(OunjePalette.secondaryText)
                    .lineLimit(1)

                if let sourceKindLabel = item.sourceKindLabel {
                    Text(sourceKindLabel)
                        .font(.system(size: 11, weight: .bold))
                        .foregroundStyle(OunjePalette.background)
                        .padding(.horizontal, 7)
                        .padding(.vertical, 3)
                        .background(
                            Capsule(style: .continuous)
                                .fill(OunjePalette.accent.opacity(0.9))
                        )
                }

                if let sourceURL = item.sourceURL, !sourceURL.isEmpty {
                    Text(sourceURL)
                        .font(.system(size: 12, weight: .medium))
                        .foregroundStyle(OunjePalette.secondaryText.opacity(0.9))
                        .lineLimit(1)
                }

                if let relativeTimestamp {
                    Text(relativeTimestamp)
                        .font(.system(size: 11, weight: .medium))
                        .foregroundStyle(OunjePalette.secondaryText)
                }
            }

            Spacer(minLength: 0)

            Text("Done")
                .font(.system(size: 11, weight: .bold))
                .foregroundStyle(OunjePalette.background)
                .padding(.horizontal, 8)
                .padding(.vertical, 4)
                .background(
                    Capsule(style: .continuous)
                        .fill(OunjePalette.accent)
                )
        }
        .padding(16)
        .frame(maxWidth: .infinity, alignment: .leading)
        .background(
            RoundedRectangle(cornerRadius: 20, style: .continuous)
                .fill(OunjePalette.surface.opacity(0.94))
                .overlay(
                    RoundedRectangle(cornerRadius: 20, style: .continuous)
                        .stroke(OunjePalette.stroke, lineWidth: 1)
                )
        )
        .contentShape(RoundedRectangle(cornerRadius: 20, style: .continuous))
        .onTapGesture {
            guard let recipe = item.savedRecipeCard else { return }
            onOpenRecipe?(recipe)
        }
    }

    private var completedFallbackIcon: some View {
        ZStack {
            RoundedRectangle(cornerRadius: 14, style: .continuous)
                .fill(OunjePalette.surface)
            Image(systemName: "checkmark.circle.fill")
                .font(.system(size: 16, weight: .bold))
                .foregroundStyle(OunjePalette.accent)
        }
    }
}

private struct PrepTabView: View {
    @EnvironmentObject private var store: MealPlanningAppStore
    @EnvironmentObject private var toastCenter: AppToastCenter
    @Binding var selectedTab: AppTab
    @Binding var requestedCookbookCycleID: String?
    let recipeTransitionNamespace: Namespace.ID
    let onSelectRecipe: (PlannedRecipe) -> Void
    @State private var isRegenerationSheetPresented = false
    @State private var selectedRegenerationFocus: PrepRegenerationFocus = .balanced
    @State private var prepLinkPulse = false

    private var currentPrepRecipeCount: Int {
        store.latestPlan?.recipes.count ?? 0
    }

    private var currentRecurringCount: Int {
        store.resolvedRecurringAnchorCount
    }

    private var showsPrepLoadingState: Bool {
        let hasRenderablePlan = store.latestPlan?.recipes.isEmpty == false
        guard !hasRenderablePlan else { return false }
        return store.isRefreshingPrepRecipes
            || store.isGenerating
            || store.isHydratingRemoteState
            || !store.hasResolvedInitialState
    }

    private var showsRegenerationPlaceholders: Bool {
        store.isGenerating && store.latestPlan?.recipes.isEmpty == false
    }

    var body: some View {
        GeometryReader { proxy in
            ScrollView {
                VStack(alignment: .leading, spacing: 26) {
                    PrepTrackerCard(store: store)

                    VStack(alignment: .leading, spacing: 16) {
                        HStack(alignment: .center, spacing: 12) {
                            HStack(alignment: .firstTextBaseline, spacing: 8) {
                                Text("Meals in")
                                    .biroHeaderFont(26)
                                    .foregroundStyle(OunjePalette.primaryText)

                                Button {
                                    requestedCookbookCycleID = store.latestPlan?.id.uuidString
                                    selectedTab = .cookbook
                                } label: {
                                        HStack(alignment: .center, spacing: 5) {
                                            Text("this prep")
                                                .sleeDisplayFont(22)
                                                .foregroundStyle(prepLinkPulse ? OunjePalette.softCream : OunjePalette.softCream.opacity(0.96))

                                            Image(systemName: "pencil")
                                                .font(.system(size: 12, weight: .semibold))
                                                .foregroundStyle(OunjePalette.softCream.opacity(prepLinkPulse ? 1 : 0.88))
                                                .scaleEffect(prepLinkPulse ? 1.08 : 0.98)
                                                .rotationEffect(.degrees(prepLinkPulse ? 6 : -3))
                                                .offset(y: prepLinkPulse ? -1 : 0)
                                                .shadow(color: .black.opacity(0.22), radius: 1, y: 1)
                                        }
                                    .padding(.horizontal, 2)
                                    .padding(.vertical, 1)
                                    .scaleEffect(prepLinkPulse ? 1.03 : 0.985)
                                    .shadow(color: OunjePalette.accent.opacity(prepLinkPulse ? 0.16 : 0.08), radius: prepLinkPulse ? 6 : 3, x: 0, y: 2)
                                }
                                .buttonStyle(.plain)
                                .contentShape(Rectangle())
                                .onAppear {
                                    guard !prepLinkPulse else { return }
                                    withAnimation(.easeInOut(duration: 1.3).repeatForever(autoreverses: true)) {
                                        prepLinkPulse = true
                                    }
                                }
                            }

                            Spacer(minLength: 12)

                            Button {
                                selectedRegenerationFocus = .balanced
                                isRegenerationSheetPresented = true
                            } label: {
                                Group {
                                    if store.isGenerating {
                                        ProgressView()
                                            .controlSize(.small)
                                            .tint(OunjePalette.softCream)
                                    } else {
                                        Image(systemName: "wand.and.stars")
                                            .font(.system(size: 18, weight: .semibold))
                                            .foregroundStyle(OunjePalette.primaryText.opacity(0.92))
                                    }
                                }
                                .frame(width: 26, height: 26)
                                .contentShape(Rectangle())
                            }
                            .buttonStyle(.plain)
                            .disabled(store.isGenerating || !(store.profile?.isPlanningReady ?? false))
                            .opacity((store.isGenerating || !(store.profile?.isPlanningReady ?? false)) ? 0.65 : 1)
                        }

                        MealsPrepCarousel(
                            plannedRecipes: store.latestPlan?.recipes ?? [],
                            showsLoadingState: showsPrepLoadingState,
                            showsRegenerationPlaceholders: showsRegenerationPlaceholders,
                            recurringRecipeIDs: store.activeRecurringPrepRecipeIDs,
                            recipeTransitionNamespace: recipeTransitionNamespace,
                            onSelectRecipe: onSelectRecipe
                        )
                        .id("\(store.latestPlan?.id.uuidString ?? "empty")::\(store.latestPlanRevision)::\(showsRegenerationPlaceholders)")
                        .padding(.horizontal, -OunjeLayout.screenHorizontalPadding)
                    }
                    .padding(.top, 4)
                }
                .padding(.horizontal, OunjeLayout.screenHorizontalPadding)
                .padding(.top, 14)
                .padding(.bottom, 12)
            }
            .scrollIndicators(.hidden)
        }
        .background(OunjePalette.background.ignoresSafeArea())
        .sheet(isPresented: $isRegenerationSheetPresented) {
            PrepRegenerationSheet(
                selectedFocus: $selectedRegenerationFocus,
                recipeCount: currentPrepRecipeCount,
                recurringCount: currentRecurringCount,
                isGenerating: store.isGenerating,
                onCancel: {
                    isRegenerationSheetPresented = false
                },
                onConfirm: { options in
                    isRegenerationSheetPresented = false
                    toastCenter.show(
                        title: "Generating prep",
                        subtitle: "Fresh meals are on the way.",
                        systemImage: "wand.and.stars"
                    )
                    Task {
                        let succeeded = await store.regeneratePrepBatch(using: options)
                        await MainActor.run {
                            if succeeded {
                                showPrepGenerationCompleteToast()
                            } else {
                                toastCenter.show(
                                    title: "Prep did not change",
                                    subtitle: "Try a stronger prompt or check your connection.",
                                    systemImage: "exclamationmark.triangle.fill"
                                )
                            }
                        }
                    }
                }
            )
            .presentationDetents([.height(500)])
            .presentationDragIndicator(.visible)
        }
    }

    private func recipeForSlot(_ index: Int) -> Recipe? {
        guard let recipes = store.latestPlan?.recipes.map(\.recipe), !recipes.isEmpty else { return nil }
        return recipes[index % recipes.count]
    }

    private func showPrepGenerationCompleteToast() {
        let recipeCard = store.latestPlan?.recipes
            .map(DiscoverRecipeCardData.init(preppedRecipe:))
            .randomElement()
        toastCenter.show(
            title: "Gen complete",
            subtitle: recipeCard?.title ?? "Fresh prep is ready.",
            systemImage: "checkmark.circle.fill",
            thumbnailURLString: recipeCard?.imageURLString ?? recipeCard?.heroImageURLString,
            destination: recipeCard.map(AppToastDestination.recipe)
        )
    }
}

private struct PrepRegenerationSheet: View {
    @Binding var selectedFocus: PrepRegenerationFocus
    let recipeCount: Int
    let recurringCount: Int
    let isGenerating: Bool
    let onCancel: () -> Void
    let onConfirm: (PrepGenerationOptions) -> Void
    @State private var targetRecipeCount: Int

    init(
        selectedFocus: Binding<PrepRegenerationFocus>,
        recipeCount: Int,
        recurringCount: Int,
        isGenerating: Bool,
        onCancel: @escaping () -> Void,
        onConfirm: @escaping (PrepGenerationOptions) -> Void
    ) {
        _selectedFocus = selectedFocus
        self.recipeCount = recipeCount
        self.recurringCount = recurringCount
        self.isGenerating = isGenerating
        self.onCancel = onCancel
        self.onConfirm = onConfirm
        let minimumRecipeCount = max(recurringCount, 1)
        let maximumRecipeCount = max(10, minimumRecipeCount)
        _targetRecipeCount = State(initialValue: min(max(recipeCount, minimumRecipeCount), maximumRecipeCount))
    }

    private var recurringCountText: String {
        recurringCount == 1 ? "1 recurring locked" : "\(recurringCount) recurring locked"
    }

    private var targetRecipeCountText: String {
        targetRecipeCount == 1 ? "1 meal" : "\(targetRecipeCount) meals"
    }

    private var minimumRecipeCount: Int {
        max(recurringCount, 1)
    }

    private var maximumRecipeCount: Int {
        max(10, minimumRecipeCount)
    }

    var body: some View {
        ZStack {
            OunjePalette.background.ignoresSafeArea()

            VStack(alignment: .leading, spacing: 10) {
                VStack(alignment: .leading, spacing: 4) {
                    SleeScriptDisplayText("Generate new prep?", size: 24, color: OunjePalette.primaryText)
                    Text("\(targetRecipeCountText) • \(recurringCountText)")
                        .font(.system(size: 12.5, weight: .medium))
                        .foregroundStyle(OunjePalette.secondaryText)
                }

                PrepRecipeCountControl(
                    value: $targetRecipeCount,
                    minimumValue: minimumRecipeCount,
                    maximumValue: maximumRecipeCount
                )

                VStack(spacing: 0) {
                    ForEach(Array(PrepRegenerationFocus.allCases.enumerated()), id: \.element.id) { index, focus in
                        Button {
                            selectedFocus = focus
                        } label: {
                            HStack(spacing: 14) {
                                Image(systemName: focus.systemImageName)
                                    .font(.system(size: 15, weight: .semibold))
                                    .foregroundStyle(selectedFocus == focus ? OunjePalette.accent.opacity(0.96) : OunjePalette.secondaryText.opacity(0.92))
                                    .frame(width: 18)

                                VStack(alignment: .leading, spacing: 2) {
                                    Text(focus.title)
                                        .font(.system(size: 14, weight: .bold))
                                        .foregroundStyle(selectedFocus == focus ? OunjePalette.primaryText : OunjePalette.primaryText.opacity(0.92))

                                    Text(focus.subtitle)
                                        .font(.system(size: 12, weight: .medium))
                                        .foregroundStyle(OunjePalette.secondaryText)
                                        .multilineTextAlignment(.leading)
                                        .lineLimit(2)
                                        .fixedSize(horizontal: false, vertical: true)
                                }

                                Spacer(minLength: 0)

                                Image(systemName: selectedFocus == focus ? "checkmark.circle.fill" : "circle")
                                    .font(.system(size: 18, weight: .semibold))
                                    .foregroundStyle(selectedFocus == focus ? OunjePalette.accent.opacity(0.96) : OunjePalette.secondaryText.opacity(0.72))
                            }
                            .padding(.vertical, 10)
                            .contentShape(Rectangle())
                        }
                        .buttonStyle(.plain)

                        if index < PrepRegenerationFocus.allCases.count - 1 {
                            Rectangle()
                                .fill(OunjePalette.stroke.opacity(0.55))
                                .frame(height: 1)
                                .padding(.vertical, 2)
                        }
                    }
                }

                Spacer(minLength: 0)

                HStack(spacing: 12) {
                    Button(action: onCancel) {
                        Text("Keep current")
                            .font(.system(size: 15, weight: .semibold))
                            .foregroundStyle(OunjePalette.primaryText)
                            .frame(maxWidth: .infinity)
                            .frame(height: 44)
                            .background(
                                RoundedRectangle(cornerRadius: 16, style: .continuous)
                                    .fill(OunjePalette.surface.opacity(0.94))
                            )
                            .overlay(
                                RoundedRectangle(cornerRadius: 16, style: .continuous)
                                    .stroke(OunjePalette.stroke.opacity(0.84), lineWidth: 1)
                            )
                    }
                    .buttonStyle(.plain)
                    .disabled(isGenerating)
                    .opacity(isGenerating ? 0.72 : 1)

                    Button {
                        onConfirm(
                            PrepGenerationOptions(
                                focus: selectedFocus,
                                targetRecipeCount: targetRecipeCount
                            )
                        )
                    } label: {
                        Text(isGenerating ? "Generating..." : "Generate prep")
                            .font(.system(size: 15, weight: .bold))
                            .foregroundStyle(OunjePalette.primaryText)
                            .frame(maxWidth: .infinity)
                            .frame(height: 44)
                            .background(
                                RoundedRectangle(cornerRadius: 16, style: .continuous)
                                    .fill(
                                        LinearGradient(
                                            colors: [
                                                OunjePalette.accent.opacity(0.94),
                                                OunjePalette.accent.opacity(0.78)
                                            ],
                                            startPoint: .topLeading,
                                            endPoint: .bottomTrailing
                                        )
                                    )
                            )
                    }
                    .buttonStyle(.plain)
                    .disabled(isGenerating)
                    .opacity(isGenerating ? 0.72 : 1)
                }
            }
            .padding(.horizontal, 20)
            .padding(.top, 12)
            .padding(.bottom, 10)
        }
    }
