    var body: some View {
        Button(action: action) {
            Image(systemName: systemName)
                .font(.system(size: 16, weight: .semibold))
                .foregroundStyle(OunjePalette.primaryText.opacity(0.88))
                .frame(width: 38, height: 38)
                .background(
                    Circle()
                        .fill(OunjePalette.surface.opacity(0.72))
                )
                .overlay(
                    Circle()
                        .stroke(OunjePalette.stroke.opacity(0.82), lineWidth: 1)
                )
                .contentShape(Circle())
        }
        .buttonStyle(.plain)
        .accessibilityLabel(accessibilityLabel)
    }
}

private struct ProfileMinimalMembershipRow: View {
    let membershipTier: OunjePricingTier
    let membershipSummary: String
    let onOpenMembership: () -> Void

    var body: some View {
        Button(action: onOpenMembership) {
            HStack(alignment: .center, spacing: 12) {
                VStack(alignment: .leading, spacing: 5) {
                    Text(membershipTier.title)
                        .font(.system(size: 16, weight: .semibold))
                        .foregroundStyle(OunjePalette.primaryText)

                    Text(membershipSummary)
                        .font(.system(size: 13, weight: .medium))
                        .foregroundStyle(OunjePalette.secondaryText)
                        .lineLimit(2)
                }

                Spacer(minLength: 10)

                Text("Plan")
                    .font(.system(size: 12, weight: .semibold))
                    .foregroundStyle(membershipTier.accentColor)

                Image(systemName: "chevron.right")
                    .font(.system(size: 12, weight: .bold))
                    .foregroundStyle(OunjePalette.secondaryText.opacity(0.55))
            }
            .padding(.vertical, 14)
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
        .overlay(alignment: .bottom) {
            Divider()
                .overlay(OunjePalette.stroke.opacity(0.55))
        }
    }
}

private struct ProfileMinimalActionGrid: View {
