private struct ProfileSettingsSectionModel: Identifiable {
    let id = UUID()
    let title: String
    let rows: [ProfileSettingsMenuRowModel]
}

private struct ProfileSettingsMenuRowModel: Identifiable {
    let id = UUID()
    let icon: String
    let iconTint: Color
    let title: String
    let detail: String
    let trailingValue: String?
    let trailingTint: Color
