                }
            }
            .padding(.vertical, 14)
            .contentShape(Rectangle())
        }
        .buttonStyle(.plain)
    }
}

private extension UNAuthorizationStatus {
    var ounjeSettingsTitle: String {
        switch self {
        case .notDetermined:
            return "Not set"
        case .denied:
            return "Off"
        case .authorized:
            return "On"
        case .provisional:
            return "Quiet"
        case .ephemeral:
            return "Temp"
        @unknown default:
            return "Unknown"
        }
    }

    var ounjeSettingsTint: Color {
        switch self {
        case .authorized, .provisional, .ephemeral:
            return OunjePalette.accent
        case .denied:
            return Color(hex: "FF8E8E")
        case .notDetermined:
            return OunjePalette.secondaryText
        @unknown default:
            return OunjePalette.secondaryText
        }
    }

    var ounjeNeutralSettingsTint: Color {
        switch self {
        case .denied:
            return Color(hex: "FF8E8E")
        default:
            return OunjePalette.secondaryText
        }
    }
}

