private actor CartArtworkImageRepository {
    static let shared = CartArtworkImageRepository()

    private var cache: [String: UIImage] = [:]
    private var inFlight: [String: Task<UIImage?, Never>] = [:]

    func image(for url: URL) async -> UIImage? {
        let key = url.absoluteString
        if let cached = cache[key] {
            return cached
        }
        if let task = inFlight[key] {
            let image = await task.value
            inFlight[key] = nil
            if let image {
                cache[key] = image
            }
            return image
        }

        let task = Task<UIImage?, Never> {
            do {
                var request = URLRequest(url: url)
                request.cachePolicy = .returnCacheDataElseLoad
                let (data, response) = try await URLSession.shared.data(for: request)
                guard let httpResponse = response as? HTTPURLResponse,
                      (200 ... 299).contains(httpResponse.statusCode),
                      let image = UIImage(data: data) else {
                    return nil
                }
                return image
            } catch {
                return nil
            }
        }

        inFlight[key] = task
        let image = await task.value
        inFlight[key] = nil
        if let image {
            cache[key] = image
        }
        return image
    }

    func prewarm(urls: [URL]) {
        for url in urls {
            let key = url.absoluteString
            guard cache[key] == nil, inFlight[key] == nil else { continue }
            inFlight[key] = Task<UIImage?, Never> {
                do {
                    var request = URLRequest(url: url)
                    request.cachePolicy = .returnCacheDataElseLoad
                    let (data, response) = try await URLSession.shared.data(for: request)
                    guard let httpResponse = response as? HTTPURLResponse,
                          (200 ... 299).contains(httpResponse.statusCode),
                          let image = UIImage(data: data) else {
                        return nil
                    }
                    return image
                } catch {
                    return nil
                }
            }
        }
    }
}

@MainActor
private final class CartArtworkImageLoader: ObservableObject {
    @Published var image: UIImage?
    private var currentKey: String?

    func load(from url: URL?) async {
        guard let url else {
            image = nil
            currentKey = nil
            return
        }

        let key = url.absoluteString
        if currentKey == key, image != nil {
            return
        }

        currentKey = key
        image = await CartArtworkImageRepository.shared.image(for: url)
    }

    static func prewarm(urls: [URL]) {
        Task(priority: .utility) {
            await CartArtworkImageRepository.shared.prewarm(urls: urls)
        }
    }
}

private struct CartCachedArtworkView<Placeholder: View>: View {
    let imageURL: URL?
    let placeholder: Placeholder

    @StateObject private var loader = CartArtworkImageLoader()

    init(imageURL: URL?, @ViewBuilder placeholder: () -> Placeholder) {
