private struct PrepDeliveryMapPlaceholderCard: View {
    let title: String
    let detail: String
    var accent: Color = OunjePalette.accent
    var visualState: PrepDeliveryMapVisualState = .loadingProfile
    var secondarySymbolName: String = "cart.fill"

    var body: some View {
        RoundedRectangle(cornerRadius: 22, style: .continuous)
            .fill(
                LinearGradient(
                    colors: [
                        OunjePalette.panel.opacity(0.98),
                        OunjePalette.surface.opacity(0.92),
                        OunjePalette.background.opacity(0.96)
                    ],
                    startPoint: .topLeading,
                    endPoint: .bottomTrailing
                )
            )
            .overlay(
                RoundedRectangle(cornerRadius: 22, style: .continuous)
                    .stroke(OunjePalette.stroke, lineWidth: 1)
            )
            .overlay {
                Group {
                    if visualState.isLoading {
                        OunjeDotLottieAssetView(fileName: "driving_car")
                            .frame(maxWidth: .infinity, maxHeight: .infinity)
                            .padding(.horizontal, 8)
                            .padding(.vertical, 10)
                    } else {
                        VStack(alignment: .leading, spacing: 14) {
                            HStack(spacing: 12) {
                                routeEndpoint(symbolName: "house.fill")

                                Spacer(minLength: 0)

                                PrepMapStateGlyph(
                                    visualState: visualState,
                                    accent: accent
                                )
                                .frame(width: 48, height: 48)

                                Spacer(minLength: 0)

                                routeEndpoint(symbolName: secondarySymbolName)
                            }
                            .frame(height: 58)

                            VStack(alignment: .leading, spacing: 6) {
                                Text(title)
                                    .font(.system(size: 14, weight: .semibold))
                                    .foregroundStyle(OunjePalette.primaryText)

                                Text(detail)
                                    .font(.system(size: 13, weight: .medium))
                                    .foregroundStyle(OunjePalette.secondaryText)
                                    .fixedSize(horizontal: false, vertical: true)
                            }
                        }
                    }
                }
                .padding(.horizontal, 18)
                .padding(.vertical, 16)
            }
    }

    private func routeEndpoint(symbolName: String) -> some View {
        ZStack {
            Circle()
                .fill(OunjePalette.surface.opacity(0.96))
                .frame(width: 38, height: 38)
                .overlay(
                    Circle()
                        .stroke(OunjePalette.stroke.opacity(0.9), lineWidth: 1)
                )

            Image(systemName: symbolName)
                .font(.system(size: 15, weight: .semibold))
                .foregroundStyle(OunjePalette.primaryText)
        }
    }
}

private struct PrepMapStateGlyph: View {
    let visualState: PrepDeliveryMapVisualState
    let accent: Color

    var body: some View {
        ZStack {
            Circle()
                .fill(OunjePalette.surface.opacity(0.84))
                .overlay(
                    Circle()
                        .stroke(accent.opacity(0.22), lineWidth: 1)
                )

            switch visualState {
            case .loadingProfile, .resolvingAddress:
                Image(systemName: visualState == .loadingProfile ? "icloud.and.arrow.down.fill" : "location.magnifyingglass")
                    .font(.system(size: 15, weight: .semibold))
                    .foregroundStyle(accent)
            case .missingAddress:
                Image(systemName: "mappin.slash")
                    .font(.system(size: 16, weight: .semibold))
                    .foregroundStyle(OunjePalette.secondaryText)
            case .addressLookupFailed:
                Image(systemName: "exclamationmark.triangle.fill")
                    .font(.system(size: 16, weight: .semibold))
                    .foregroundStyle(Color.orange)
            case .resolved:
                Image(systemName: "checkmark")
                    .font(.system(size: 16, weight: .bold))
                    .foregroundStyle(accent)
            }
        }
        .clipShape(Circle())
    }
}

