                Image(systemName: "magnifyingglass")
                    .font(.system(size: 17, weight: .bold))
                    .scaleEffect(iconScale)
                    .foregroundStyle(isActive ? Color.black.opacity(0.88) : OunjePalette.softCream.opacity(0.88))
