private enum IngredientMonogramFormatter {
    static func monogram(for name: String) -> String {
        let parts = name
            .split(whereSeparator: { !$0.isLetter && !$0.isNumber })
            .map(String.init)
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
            .filter { $0.rangeOfCharacter(from: .letters) != nil }
            .filter { $0.count > 1 }

        if parts.count >= 2 {
            let initials = parts.prefix(2).compactMap { $0.first.map { String($0).uppercased() } }.joined()
            if !initials.isEmpty {
                return initials
            }
        }

        if let first = parts.first {
            let pair = String(first.prefix(2)).uppercased()
            if !pair.isEmpty {
                return pair
            }
        }

        return "•"
    }
}

