                    .blendMode(.softLight)
                }
                    .mask(
                        LinearGradient(
                            colors: [
                                .black,
                            .black.opacity(0.88),
                                .clear
                            ],
                            startPoint: .top,
                            endPoint: .bottom
                        )
                    )
                .frame(height: proxy.safeAreaInsets.top + 10)

                Spacer()
            }
            .ignoresSafeArea()
        }
        .allowsHitTesting(false)
        .accessibilityHidden(true)
    }
}

