    let completedAt: String?
    let selectedStore: String?
    let preferredStore: String?
    let strictStore: String?
    let sessionSource: String?
    let success: Bool
    let partialSuccess: Bool
    let items: [InstacartRunLogItemPayload]
    let cartUrl: String?

